INSERT INTO "course_landings" ("id", "course_id", "user_id", "slug", "headline", "subtitle", "benefits", "summary", "testimonial_name", "testimonial_text", "cta_text", "is_published", "created_at", "updated_at", "template_id", "custom_colors", "layout_blocks", "custom_css", "custom_domain", "show_branding", "logo_url") VALUES ('eb0f4a66-0b33-48f8-9596-1b627e76084f', '0d7c9a9f-8cc3-4f60-8153-52bf84c71039', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'fundamentos-de-programacao-0d7c9a', 'Domine os Fundamentos da Programação e Inicie sua Carreira Tech', 'Um guia didático e prático para iniciantes aprenderem a lógica computacional e as bases do desenvolvimento de software.', '["Voc\u00ea vai aprender a pensar como um programador, dominando a l\u00f3gica e algoritmos do zero.", "Voc\u00ea vai aprender a dominar vari\u00e1veis, tipos de dados e operadores para manipular informa\u00e7\u00f5es.", "Voc\u00ea vai aprender a criar programas inteligentes com estruturas de decis\u00e3o e repeti\u00e7\u00e3o automatizadas.", "Voc\u00ea vai aprender a escrever c\u00f3digo limpo e reutiliz\u00e1vel atrav\u00e9s de fun\u00e7\u00f5es e boas pr\u00e1ticas.", "Ao final, voc\u00ea ser\u00e1 capaz de organizar dados de forma eficiente e desenvolver seus pr\u00f3prios projetos pr\u00e1ticos."]', 'Este curso oferece uma base sólida para quem deseja entrar no mundo da tecnologia, cobrindo desde a lógica binária até estruturas de dados avançadas. Você aprenderá a traduzir problemas em soluções algorítmicas, utilizando as melhores práticas do mercado para escrever códigos limpos, eficientes e profissionais. É o ponto de partida ideal para transformar curiosidade em habilidade técnica real.', 'Lucas A.', 'Eu não sabia nada de programação e sempre achei a lógica algo impossível. Esse curso explicou passo a passo, de forma tão didática, que hoje já consigo criar meus próprios scripts e entender o que estou escrevendo!', 'Quero me inscrever', FALSE, '2026-03-11T18:02:32.678773+00:00', '2026-03-11T18:07:28.945+00:00', 'template1', '{"primary": "#7c3aed"}', '[]', NULL, NULL, TRUE, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "course_landings" ("id", "course_id", "user_id", "slug", "headline", "subtitle", "benefits", "summary", "testimonial_name", "testimonial_text", "cta_text", "is_published", "created_at", "updated_at", "template_id", "custom_colors", "layout_blocks", "custom_css", "custom_domain", "show_branding", "logo_url") VALUES ('c9e12b23-ee71-4b65-ab40-42d4f11f6876', '9fc801fa-7fda-434b-ac28-20c9a5938908', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'introducao-a-auditoria-operacional-9fc801', 'Domine a Auditoria Operacional e Transforme a Gestão Pública', 'O guia prático para auditores e controladores focarem na economia, eficiência e resultados reais para a sociedade.', '["Dominar a metodologia dos 4 E''s (Economia, Efici\u00eancia, Efic\u00e1cia e Equidade) aplicada aos Tribunais de Contas.", "Realizar um planejamento estrat\u00e9gico robusto utilizando crit\u00e9rios SMART e matriz de riscos.", "Coletar e validar evid\u00eancias incontest\u00e1veis atrav\u00e9s de t\u00e9cnicas avan\u00e7adas de triangula\u00e7\u00e3o e an\u00e1lise documental.", "Formular achados fundamentados nos 4 C''s e elaborar relat\u00f3rios de alto impacto para a gest\u00e3o p\u00fablica.", "Monitorar a implementa\u00e7\u00e3o de recomenda\u00e7\u00f5es para garantir a melhoria cont\u00ednua e a entrega de valor \u00e0 sociedade."]', 'Este curso oferece uma formação completa em Auditoria Operacional, cobrindo desde os fundamentos éticos até as técnicas avançadas de monitoramento de resultados. Você aprenderá a planejar, executar e relatar auditorias que vão além da conformidade legal, focando na otimização de recursos e na eficácia das políticas públicas nos Tribunais de Contas e controladorias.', 'Ricardo M. S.', 'O curso mudou minha perspectiva sobre auditoria. Saí do foco restrito à legalidade e agora consigo propor recomendações que realmente melhoram a gestão e geram economia para o município.', 'Quero me inscrever', TRUE, '2026-03-12T20:41:19.177298+00:00', '2026-03-12T20:41:19.177298+00:00', 'template1', '{"primary": "#7c3aed"}', '[]', NULL, NULL, TRUE, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "course_landings" ("id", "course_id", "user_id", "slug", "headline", "subtitle", "benefits", "summary", "testimonial_name", "testimonial_text", "cta_text", "is_published", "created_at", "updated_at", "template_id", "custom_colors", "layout_blocks", "custom_css", "custom_domain", "show_branding", "logo_url") VALUES ('3299c653-bb81-49eb-bdae-a42049ea6176', '43c41ec9-d179-4fe6-9506-dbdb0bec3acc', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'curso-de-introducao-a-programacao-em-python-43c41e', 'Domine Python do zero e construa ferramentas reais para o mercado de tecnologia.', 'Um curso prático e didático para iniciantes em programação que desejam criar, testar e distribuir aplicações Python profissionais.', '["Voc\u00ea vai aprender a dominar estruturas de dados como listas e dicion\u00e1rios para organizar informa\u00e7\u00f5es de forma eficiente.", "Ao final, voc\u00ea ser\u00e1 capaz de criar arquiteturas limpas usando Programa\u00e7\u00e3o Orientada a Objetos para modelar entidades do mundo real.", "Voc\u00ea vai aprender a manipular arquivos CSV e JSON, garantindo que seus dados sejam persistidos com seguran\u00e7a.", "Ao final, voc\u00ea ser\u00e1 capaz de escrever testes automatizados e logs profissionais para criar softwares robustos e livres de bugs.", "Voc\u00ea vai aprender a empacotar e distribuir seus pr\u00f3prios utilit\u00e1rios Python no PyPI para uso de toda a comunidade."]', 'Este curso oferece uma jornada completa pelos fundamentos do Python, desde a sintaxe inicial até a criação de utilitários avançados. Você explorará manipulação de dados, automação com scripts, Programação Orientada a Objetos e boas práticas de engenharia de software, como testes automatizados e logs. É a formação ideal para transformar lógica de programação em soluções concretas e valiosas para o mundo real.', 'Lucas R.', 'O curso mudou minha percepção sobre programação. A didática é excelente e os módulos sobre automação e testes me deram a confiança que eu precisava para começar meus próprios projetos profissionais.', 'Quero me inscrever', TRUE, '2026-03-12T23:03:05.943261+00:00', '2026-03-12T23:03:05.943261+00:00', 'template1', '{"primary": "#7c3aed"}', '[]', NULL, NULL, TRUE, NULL) ON CONFLICT DO NOTHING;

