-- Data for courses
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('4b346bfb-a376-401e-b12c-87292f5e6820', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Teste', 'Este curso ''Teste'' foi desenvolvido para um público geral, abordando o tópico ''Teste'' de maneira profissional e informativa. O conteúdo é apresentado em português do Brasil e está estruturado em um único módulo para oferecer uma experiência de aprendizado concisa e focada.', 'Teste', NULL, NULL, 'pt-BR', 'draft', FALSE, FALSE, FALSE, '2026-03-01T23:19:49.366877+00:00', '2026-03-01T23:19:49.366877+00:00', FALSE, FALSE, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('3ea6695e-4a55-4561-be2e-cfcde9cd30d7', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Introdução às Redes Neurais Artificiais', 'Este curso apresenta os fundamentos das redes neurais artificiais, explicando como elas funcionam, seus principais componentes, tipos básicos de redes e aplicações práticas em inteligência artificial e aprendizado de máquina. Voltado para iniciantes em inteligência artificial e para estudantes universitários de tecnologia, o curso pressupõe conhecimentos básicos de programação.', 'Este curso apresenta os fundamentos das redes neurais artificiais, explicando como elas funcionam, seus principais componentes, tipos básicos de redes e aplicações práticas em inteligência artificial e aprendizado de máquina.', 'Iniciantes em inteligência artificial, estudantes universitários de tecnologia e pessoas com conhecimentos básicos de programação.', 'profissional', 'pt-BR', 'published', TRUE, TRUE, FALSE, '2026-03-01T23:23:01.127072+00:00', '2026-03-01T23:33:06.202891+00:00', FALSE, FALSE, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('d997aef8-a4a2-48fb-98dd-c8a37bd06fd0', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Inteligência Artificial para Aumentar a Produtividade no Trabalho', 'Este curso foi projetado para capacitá-lo a utilizar a Inteligência Artificial (IA) como uma ferramenta poderosa para otimizar e automatizar tarefas cotidianas em seu ambiente de trabalho. Abordaremos desde os conceitos fundamentais da IA até a aplicação prática de ferramentas acessíveis, permitindo que você aumente sua eficiência, reduza o tempo gasto em atividades repetitivas e concentre seus esforços em tarefas de maior valor estratégico. Desenvolvido para profissionais de diversas áreas, este treinamento visa desmistificar a IA e torná-la uma aliada indispensável para sua produtividade.', 'Automação de Tarefas no Trabalho Usando Inteligência Artificial', 'Profissionais não técnicos (administrativo, marketing, RH, gestão, empreendedores, estudantes).', 'profissional', 'pt-BR', 'published', TRUE, TRUE, FALSE, '2026-03-05T20:17:44.426445+00:00', '2026-03-05T20:25:10.670856+00:00', FALSE, FALSE, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('3bbd038f-eab9-4b09-97c1-97e87a6deab2', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Inteligência Artificial na Prática: Aplicações Reais para Profissionais Não Técnicos', 'Este curso oferece uma introdução prática e acessível ao universo da Inteligência Artificial (IA), com foco em suas aplicações reais para profissionais que não possuem formação técnica. Exploraremos como a IA pode ser uma aliada poderosa na tomada de decisões, otimização de processos e inovação no ambiente de trabalho, apresentando ferramentas práticas e exemplos concretos. O objetivo é capacitar você a identificar oportunidades para aplicar a IA em sua rotina profissional, impulsionando sua carreira e seus projetos.', 'Introdução prática ao uso da Inteligência Artificial no dia a dia profissional, com foco em aplicações reais, ferramentas acessíveis e tomada de decisão, sem exigir conhecimentos técnicos ou programação.', 'Profissionais de diversas áreas, professores, gestores, empreendedores, estudantes e pessoas interessadas em aplicar Inteligência Artificial no trabalho, mesmo sem formação técnica.', 'profissional', 'pt-BR', 'published', TRUE, TRUE, TRUE, '2026-03-03T20:26:43.072924+00:00', '2026-03-03T20:28:52.879521+00:00', FALSE, FALSE, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('0d7c9a9f-8cc3-4f60-8153-52bf84c71039', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Fundamentos de Programação', 'Este curso introdutório tem como objetivo apresentar os fundamentos da programação de forma didática e acessível. Abordaremos a lógica computacional, os conceitos básicos de estruturas de dados, a importância das boas práticas de codificação e o desenvolvimento de projetos práticos para solidificar o aprendizado. Destina-se a iniciantes que desejam dar os primeiros passos no mundo da programação e do desenvolvimento de software.', 'Introdução à programação: lógica computacional, estruturas de dados básicas, boas práticas de código e desenvolvimento de projetos práticos', 'Iniciantes em programação e desenvolvimento de software', 'didatico', 'pt-BR', 'published', TRUE, TRUE, TRUE, '2026-03-11T17:55:32.350185+00:00', '2026-03-11T18:08:57.332237+00:00', FALSE, TRUE, '0d7c9a9f', NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('6188aa25-fdd1-463b-9584-559d5e97516c', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Fundamentos de Programação', 'Este curso introdutório aos Fundamentos de Programação visa apresentar aos iniciantes os conceitos essenciais para o desenvolvimento de software. Abordaremos o pensamento lógico-computacional, as estruturas de dados mais comuns, a importância das boas práticas de codificação e o desenvolvimento de projetos práticos para solidificar o aprendizado. Ao final, os alunos estarão aptos a dar os primeiros passos no universo da programação com confiança e embasamento.', 'Introdução à programação: lógica computacional, estruturas de dados básicas, boas práticas de código e desenvolvimento de projetos práticos', 'Iniciantes em programação e desenvolvimento de software', 'didatico', 'pt-BR', 'draft', TRUE, TRUE, TRUE, '2026-03-11T17:36:50.254912+00:00', '2026-03-11T17:36:50.254912+00:00', FALSE, FALSE, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('f1297994-6c4d-4ff4-ac87-d80bd625265b', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Fundamentos de Programação', 'Este curso oferece uma introdução completa ao universo da programação, cobrindo desde os alicerces da lógica computacional até a aplicação prática em projetos. Aprenda sobre estruturas de dados essenciais, as melhores práticas para escrever código limpo e eficiente, e desenvolva a capacidade de solucionar problemas de forma algorítmica. Ideal para quem deseja dar os primeiros passos no desenvolvimento de software e construir uma base sólida para o aprendizado contínuo.', 'Introdução à programação: lógica computacional, estruturas de dados básicas, boas práticas de código e desenvolvimento de projetos práticos', 'Iniciantes em programação e desenvolvimento de software', 'didatico', 'pt-BR', 'draft', TRUE, TRUE, TRUE, '2026-03-11T17:46:35.006957+00:00', '2026-03-11T17:46:35.006957+00:00', FALSE, FALSE, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('ae489973-af0a-4434-bebf-0420b7266596', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Negotiation and Persuasion for B2B Sales', 'This course aims to empower sales professionals and account managers experienced in transactions to develop advanced negotiation and persuasion skills, which are essential for complex sales cycles in the B2B environment. We will cover everything from the fundamentals of buyer psychology and qualification frameworks to effective objection handling strategies and the application of ethical persuasion to build long-lasting relationships and maximize results.', 'Técnicas avançadas de negociação para ciclos de venda complexos, incluindo psicologia do comprador, frameworks de qualificação, gestão de objeções e persuasão ética', 'Profissionais de vendas e account managers com experiência em vendas transacionais que querem evoluir para vendas consultivas em ambiente B2B', 'profissional', 'en-US', 'draft', TRUE, TRUE, FALSE, '2026-03-12T04:40:54.522295+00:00', '2026-03-12T04:40:54.522295+00:00', FALSE, FALSE, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO "courses" ("id", "user_id", "title", "description", "theme", "target_audience", "tone", "language", "status", "include_quiz", "include_flashcards", "include_images", "created_at", "updated_at", "use_sources", "tutor_enabled", "tutor_slug", "workspace_id") VALUES ('9fc801fa-7fda-434b-ac28-20c9a5938908', '389a5d7f-5d24-46ed-a315-e4e86ec53c3b', 'Introdução à Auditoria Operacional', 'Este curso foi cuidadosamente elaborado para fornecer aos auditores dos tribunais de contas estaduais e municipais, bem como aos controladores municipais, uma compreensão aprofundada dos princípios e práticas da auditoria operacional. O conteúdo abordará desde os fundamentos e o planejamento estratégico, passando pela execução, análise de evidências, até a elaboração de relatórios, contribuindo para a melhoria contínua dos processos de auditoria.', 'O conteúdo abordará desde os fundamentos e o planejamento estratégico, passando pela execução, análise de evidências, até a elaboração de relatórios, contribuindo para a melhoria contínua dos processos de auditoria.', 'auditores dos tribunais de contas estaduais e municipais, bem como controladores municipais', 'profissional', 'pt-BR', 'published', TRUE, TRUE, TRUE, '2026-03-12T20:30:18.605628+00:00', '2026-04-30T04:09:17.180335+00:00', FALSE, TRUE, '9fc801fa', NULL) ON CONFLICT DO NOTHING;
