INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0c1945a1-acb1-4da0-a472-18ac75116e03', '1ab5cbcf-b36f-4143-a86f-f6daf38797cf', 'Qual a função básica de um neurônio artificial?', '["Armazenar dados de forma permanente", "Realizar opera\u00e7\u00f5es matem\u00e1ticas simples sobre as entradas ponderadas e aplicar uma fun\u00e7\u00e3o de ativa\u00e7\u00e3o", "Gerenciar a comunica\u00e7\u00e3o entre diferentes redes neurais", "Controlar a ilumina\u00e7\u00e3o de um display"]', 1, 'Um neurônio artificial recebe entradas, as pondera, soma-as e aplica uma função de ativação para gerar uma saída.', '2026-03-01T23:23:30.250085+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a13014d3-c4c1-4bff-8128-21328d2f6f7e', '07d8198d-f341-4110-8a8c-a568f6b42110', 'O que são os ''pesos'' em uma rede neural?', '["A quantidade de dados que a rede pode processar", "Os par\u00e2metros que determinam a for\u00e7a da conex\u00e3o entre os neur\u00f4nios e s\u00e3o ajustados durante o treinamento", "O n\u00edvel de acur\u00e1cia da rede", "Fatores externos que influenciam o resultado"]', 1, 'Pesos são os multiplicadores das entradas de um neurônio. O ajuste desses pesos é a essência do aprendizado em redes neurais.', '2026-03-01T23:24:04.815887+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('673c354c-57c3-451a-9da2-d95fd9852b3b', '07d8198d-f341-4110-8a8c-a568f6b42110', 'Qual é o objetivo principal da Função de Custo (ou Perda)?', '["Maximizar a velocidade de treinamento", "Medir o qu\u00e3o bem o modelo est\u00e1 performando, quantificando o erro entre a previs\u00e3o e o valor real", "Aumentar a complexidade da rede", "Reduzir a quantidade de mem\u00f3ria utilizada"]', 1, 'A função de custo quantifica o erro do modelo. O objetivo do treinamento é minimizar essa função, reduzindo o erro.', '2026-03-01T23:24:04.815887+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('8d292140-f6f5-4fbf-893e-dcb4c16f9825', '07d8198d-f341-4110-8a8c-a568f6b42110', 'A retropropagação (backpropagation) é um algoritmo usado para:', '["Gerar os dados de entrada para a rede", "Calcular a previs\u00e3o da rede", "Ajustar os pesos da rede neural com base no erro calculado", "Visualizar a arquitetura da rede"]', 2, 'Backpropagation é o processo de propagar o erro da camada de saída de volta para as camadas anteriores, ajustando os pesos em cada passo.', '2026-03-01T23:24:04.815887+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('9423e1ba-526f-4113-acf9-1459289caa38', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Qual tipo de rede neural é mais comumente utilizado para tarefas de reconhecimento de imagem?', '["Rede Neural Recorrente (RNN)", "Perceptron Multicamadas (MLP)", "Rede Neural Convolucional (CNN)", "Rede Neural por Fun\u00e7\u00e3o de Base Radial (RBFN)"]', 2, 'CNNs são altamente eficazes em capturar padrões espaciais em imagens, tornando-as ideais para reconhecimento e classificação de imagens.', '2026-03-01T23:24:31.712459+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0d9416cc-58f3-404b-8d22-95df4942ec89', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Para que tipo de dados as Redes Neurais Recorrentes (RNNs) são especialmente adequadas?', '["Dados de alta dimensionalidade espacial", "Dados estruturados em tabelas", "Dados sequenciais ou temporais, como texto e s\u00e9ries temporais", "Imagens est\u00e1ticas sem contexto temporal"]', 2, 'RNNs possuem ''memória'' que lhes permite processar sequências, lembrando informações de passos anteriores, o que é crucial para dados sequenciais.', '2026-03-01T23:24:31.712459+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f084e8b1-8810-47d1-a1b4-da10dab2fa78', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Qual das seguintes NÃO é uma aplicação comum de Redes Neurais?', '["Reconhecimento Facial", "Tradu\u00e7\u00e3o Autom\u00e1tica", "Previs\u00e3o do Tempo", "C\u00e1lculo de Juros de Empr\u00e9stimos Banc\u00e1rios Tradicionais (sem an\u00e1lise preditiva)"]', 3, 'Enquanto redes neurais podem ser usadas para otimizar ou analisar dados financeiros complexos, o cálculo direto de juros de empréstimos em modelos tradicionais geralmente não requer o uso de IA ou redes neurais, sendo um processo mais determinístico.', '2026-03-01T23:24:31.712459+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('9eede667-be62-4fe3-a5d5-6fcb428d863e', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'Qual das seguintes características é essencial para uma evidência de auditoria ser considerada confiável?', '["Ser extensa e detalhada.", "Ser obtida exclusivamente de fontes internas.", "Ser relevante, competente e suficiente.", "Ser apresentada em formato digital."]', 2, 'A confiabilidade da evidência está diretamente ligada à sua relevância para o objetivo da auditoria, à sua competência (validade da fonte e método) e suficiência (quantidade adequada).', '2026-03-12T20:31:23.162974+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('9097f7d1-8a2c-4444-90ee-e7b5d35ffd39', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'Qual técnica de coleta de evidências é mais adequada para observar o fluxo de um processo em tempo real?', '["An\u00e1lise documental.", "Entrevista com gestores.", "Observa\u00e7\u00e3o direta (in loco).", "Question\u00e1rios padronizados."]', 2, 'A observação direta permite ao auditor visualizar o processo em funcionamento, identificando gargalos ou desvios que não seriam perceptíveis por outros métodos.', '2026-03-12T20:31:23.162974+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0a16f707-43e9-4e3e-97ca-0d51344bb2d3', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'Na execução da auditoria operacional, qual a importância da comunicação contínua com a entidade auditada?', '["Apenas para agendamento de reuni\u00f5es.", "Para divulgar as conclus\u00f5es finais da auditoria previamente ao relat\u00f3rio.", "Para esclarecer d\u00favidas, solicitar informa\u00e7\u00f5es adicionais e validar entendimentos, promovendo transpar\u00eancia e evitando surpresas.", "Para obter aprova\u00e7\u00e3o pr\u00e9via das descobertas."]', 2, 'A comunicação contínua e transparente é fundamental para um bom relacionamento, esclarecimento de pontos, ajuste de rota e para que a entidade auditada não seja surpreendida pelas constatações.', '2026-03-12T20:31:23.162974+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('19fbd8de-fea5-4cda-9cf7-ed3a29057a9c', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'Qual é o principal objetivo da auditoria operacional?', '["Garantir a conformidade legal e regulat\u00f3ria.", "Avaliar a efic\u00e1cia, efici\u00eancia e economicidade dos processos.", "Determinar a fidedignidade das demonstra\u00e7\u00f5es financeiras.", "Identificar fraudes e desfalques em organiza\u00e7\u00f5es p\u00fablicas."]', 1, 'O principal objetivo da auditoria operacional é avaliar a performance da gestão em termos de eficácia, eficiência e economicidade, buscando identificar oportunidades de melhoria.', '2026-03-12T20:31:23.609347+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('de41d9ea-a5bf-46be-950e-54a9496e74e1', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'Qual a diferença central entre auditoria operacional e auditoria financeira?', '["A auditoria operacional foca em conformidade, enquanto a financeira foca em desempenho.", "A auditoria operacional verifica processos, a financeira verifica demonstra\u00e7\u00f5es cont\u00e1beis.", "A auditoria operacional \u00e9 obrigat\u00f3ria para todos os \u00f3rg\u00e3os p\u00fablicos, a financeira n\u00e3o.", "A auditoria operacional n\u00e3o utiliza crit\u00e9rios, a financeira sim."]', 1, 'A auditoria operacional avalia processos, sistemas e programas para otimização, enquanto a auditoria financeira atesta a fidedignidade e conformidade das demonstrações contábeis com as normas aplicáveis.', '2026-03-12T20:31:23.609347+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6d0e1824-d88e-4de1-a528-67242422b03f', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'Os Princípios Fundamentais de Auditoria do setor público, conforme a INTOSAI, enfatizam qual aspecto principal para a auditoria operacional?', '["Independ\u00eancia do auditor.", "Materialidade e relev\u00e2ncia.", "Avalia\u00e7\u00e3o da rela\u00e7\u00e3o custo-benef\u00edcio.", "Foco na preven\u00e7\u00e3o de fraudes."]', 0, 'A independência é um princípio fundamental para garantir a objetividade e imparcialidade do processo de auditoria operacional, conforme as normas da INTOSAI.', '2026-03-12T20:31:23.609347+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('67916b81-40b8-46f2-aecc-c4e4449326b8', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'Qual a primeira e mais importante etapa do planejamento de uma auditoria operacional?', '["Coleta de evid\u00eancias.", "Defini\u00e7\u00e3o dos objetivos da auditoria.", "Elabora\u00e7\u00e3o do relat\u00f3rio preliminar.", "Sele\u00e7\u00e3o da equipe de auditoria."]', 1, 'A definição clara dos objetivos da auditoria é o ponto de partida, pois orientará todo o processo, desde a coleta de informações até a elaboração das recomendações.', '2026-03-12T20:31:27.644532+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('bc1c4c7e-9ae1-4a4a-8db5-d403e3d5d9d1', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'O que o auditor deve analisar para identificar os principais riscos em uma auditoria operacional?', '["Somente os balan\u00e7os financeiros dos \u00faltimos dois anos.", "O hist\u00f3rico de reclama\u00e7\u00f5es de clientes/cidad\u00e3os.", "Os processos, controles internos e ambiente em que a entidade opera, considerando a probabilidade e o impacto de falhas.", "A reputa\u00e7\u00e3o da alta dire\u00e7\u00e3o da organiza\u00e7\u00e3o."]', 2, 'A análise de riscos deve ser abrangente, considerando os processos, controles internos e o ambiente operacional para identificar as áreas mais vulneráveis e que mereçam maior atenção na auditoria.', '2026-03-12T20:31:27.644532+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('22236738-ca03-4515-8790-22c121873f65', 'c4911477-5546-4ace-9680-00d374416369', 'Qual a principal vantagem de utilizar IA para analisar grandes volumes de dados em comparação com métodos manuais?', '["Diminui\u00e7\u00e3o da complexidade da an\u00e1lise.", "Capacidade de processar e identificar padr\u00f5es em uma velocidade e escala imposs\u00edveis manualmente.", "Elimina\u00e7\u00e3o da necessidade de qualquer interven\u00e7\u00e3o humana na an\u00e1lise.", "Aumento da probabilidade de erros de c\u00e1lculo."]', 1, 'A IA permite processar vastas quantidades de dados de forma rápida e identificar padrões complexos que seriam imperceptíveis ou demandariam um tempo proibitivo para análise manual.', '2026-03-03T20:27:07.600071+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b764d58f-6d5d-4667-bae0-3249d8f9b67a', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'Qual a finalidade da matriz de risco e materialidade no planejamento da auditoria operacional?', '["Definir a hierarquia da equipe de auditoria.", "Identificar \u00e1reas cr\u00edticas que demandam maior foco e aloca\u00e7\u00e3o de recursos durante a auditoria.", "Calcular o custo total da auditoria.", "Priorizar as entrevistas com a alta dire\u00e7\u00e3o."]', 1, 'A matriz de risco e materialidade é uma ferramenta essencial para direcionar os esforços de auditoria para as áreas com maior potencial de impacto ou fragilidade, otimizando o uso dos recursos.', '2026-03-12T20:31:27.644532+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('60c5dd65-ee24-4804-bcf7-3edea0a836db', 'c4911477-5546-4ace-9680-00d374416369', 'Para um profissional de finanças, como uma ferramenta de IA pode auxiliar na previsão de desempenho de investimentos?', '["Preenchendo automaticamente planilhas financeiras.", "Analisando indicadores econ\u00f4micos hist\u00f3ricos e em tempo real, not\u00edcias de mercado e comportamento de ativos para identificar padr\u00f5es preditivos.", "Criando relat\u00f3rios de vendas fict\u00edcios.", "Gerando gr\u00e1ficos coloridos sem embasamento."]', 1, 'A IA pode processar múltiplos indicadores e correlações para gerar previsões mais embasadas sobre o desempenho futuro de investimentos.', '2026-03-03T20:27:07.600071+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4df7fe31-ee51-44ad-8ce5-74fecb1794c9', 'c4911477-5546-4ace-9680-00d374416369', 'Qual o papel da visualização de dados no contexto da IA para geração de insights?', '["A visualiza\u00e7\u00e3o de dados \u00e9 desnecess\u00e1ria quando se usa IA.", "A visualiza\u00e7\u00e3o de dados ajuda a apresentar os insights gerados pela IA de forma clara e compreens\u00edvel para tomadores de decis\u00e3o.", "A visualiza\u00e7\u00e3o de dados \u00e9 apenas para fins est\u00e9ticos e n\u00e3o contribui para a an\u00e1lise.", "A visualiza\u00e7\u00e3o de dados limita a capacidade da IA de encontrar padr\u00f5es."]', 1, 'Gráficos e dashboards criados com base nos insights da IA transformam dados complexos em informações visuais acessíveis, facilitando a compreensão e a comunicação de descobertas.', '2026-03-03T20:27:07.600071+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f63dbccf-783b-408d-bf87-397488f3d217', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'Qual tipo de ferramenta de IA seria mais útil para um redator que busca otimizar a criação de legendas para redes sociais?', '["Uma plataforma de an\u00e1lise preditiva de mercado.", "Um gerador de texto assistido por IA.", "Um software de reconhecimento de imagem.", "Um sistema de tradu\u00e7\u00e3o autom\u00e1tica."]', 1, 'Ferramentas de geração de texto assistidas por IA podem ajudar a criar e refinar legendas de forma mais eficiente, sugerindo ideias e melhorando o estilo.', '2026-03-03T20:27:14.161699+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('69419cd3-03ef-48ae-b975-66f187a39d6f', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'Se um profissional precisa rapidamente compilar e resumir informações de diversos documentos, qual tipo de ferramenta de IA seria ideal?', '["Um sistema de chatbot para atendimento ao cliente.", "Uma ferramenta de an\u00e1lise de sentimentos.", "Um software de gerenciamento de projetos.", "Uma ferramenta de resumo e an\u00e1lise de texto."]', 3, 'Ferramentas especializadas em resumo e análise de texto podem processar múltiplos documentos e extrair informações chave de forma rápida e eficaz.', '2026-03-03T20:27:14.161699+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2de13153-4728-4bdd-8338-1bf634e056e6', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'Ao escolher uma ferramenta de IA sem código, qual o fator mais importante a considerar para um profissional não técnico?', '["O n\u00famero de linhas de c\u00f3digo que o software utiliza.", "A complexidade da interface e a curva de aprendizado.", "A performance do hardware necess\u00e1rio para rodar o software.", "A opini\u00e3o de desenvolvedores de IA sobre a ferramenta."]', 1, 'Para um profissional não técnico, a facilidade de uso e uma interface intuitiva são cruciais para garantir que a ferramenta possa ser integrada à rotina de trabalho sem barreiras técnicas.', '2026-03-03T20:27:14.161699+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('e3e9447f-579d-46d4-b660-28b63631d2b0', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'Qual o principal objetivo deste curso para profissionais não técnicos em relação à Inteligência Artificial?', '["Tornar-se um programador de IA.", "Entender as aplica\u00e7\u00f5es pr\u00e1ticas da IA e como utiliz\u00e1-la para tomar decis\u00f5es.", "Desenvolver algoritmos complexos de aprendizado de m\u00e1quina.", "Criar novas redes neurais artificiais."]', 1, 'O curso visa capacitar profissionais para reconhecer e aplicar a IA em suas atividades, sem exigir conhecimentos de programação. O foco é na usabilidade e na tomada de decisão.', '2026-03-03T20:27:14.823875+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('01620f2c-f0f4-473b-b7a6-eeb9bfea7b00', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'Em que a Inteligência Artificial se diferencia da automação tradicional de processos?', '["A IA n\u00e3o utiliza algoritmos, apenas regras pr\u00e9-definidas.", "A IA pode aprender com dados e adaptar seu comportamento, enquanto a automa\u00e7\u00e3o tradicional \u00e9 est\u00e1tica.", "A IA \u00e9 exclusiva para tarefas criativas, a automa\u00e7\u00e3o para tarefas repetitivas.", "A automa\u00e7\u00e3o \u00e9 mais avan\u00e7ada que a IA em termos de aprendizado."]', 1, 'A principal diferença reside na capacidade de aprendizado e adaptação. A IA aprende com dados e pode otimizar seu desempenho ao longo do tempo, indo além de regras fixas.', '2026-03-03T20:27:14.823875+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('5ec85316-abd5-4688-ab0c-85b0fb9bc9fc', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'Qual destes NÃO é um benefício direto da aplicação da IA em um ambiente profissional para um usuário não técnico?', '["Aumento da efici\u00eancia operacional.", "Melhoria na qualidade das decis\u00f5es estrat\u00e9gicas.", "Redu\u00e7\u00e3o da necessidade de pensamento cr\u00edtico e an\u00e1lise humana.", "Personaliza\u00e7\u00e3o de experi\u00eancias para clientes."]', 2, 'A IA é uma ferramenta que aprimora o pensamento crítico e a análise humana, fornecendo insights e automação, mas não substitui a necessidade de julgamento e raciocínio do profissional.', '2026-03-03T20:27:14.823875+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('d3796b99-8767-420a-918f-42e8c9db9789', '040f437a-eaf3-433c-be93-36008614769b', 'Qual habilidade se torna cada vez mais importante no mercado de trabalho com a crescente adoção da IA?', '["Habilidade de programar em todas as linguagens.", "Capacidade de adapta\u00e7\u00e3o, pensamento cr\u00edtico e resolu\u00e7\u00e3o criativa de problemas.", "Execu\u00e7\u00e3o repetitiva de tarefas manuais.", "Memoriza\u00e7\u00e3o de grandes volumes de informa\u00e7\u00e3o."]', 1, 'Com a IA automatizando tarefas rotineiras, as habilidades intrinsecamente humanas como criatividade, pensamento crítico, adaptabilidade e resolução de problemas complexos tornam-se mais valiosas.', '2026-03-03T20:27:42.968231+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('bf7b1dc1-88eb-4179-8b69-7e0ee7168388', '040f437a-eaf3-433c-be93-36008614769b', 'Na colaboração humano-IA, qual é o papel principal do profissional humano?', '["Executar todas as tarefas que a IA pode fazer.", "Ser um supervisor passivo da IA.", "Supervisionar, interpretar os resultados da IA, tomar decis\u00f5es estrat\u00e9gicas e aplicar julgamento \u00e9tico.", "Delegar completamente o aprendizado \u00e0 IA."]', 2, 'O profissional humano atua como o tomador de decisão final, supervisionando a IA, interpretando seus resultados, aplicando conhecimento contextual e garantindo o uso ético da tecnologia.', '2026-03-03T20:27:42.968231+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('271e0b10-a6c0-4b7b-9ded-d8af0cb6de5a', '040f437a-eaf3-433c-be93-36008614769b', 'Qual CONSIDERACÃO ética é fundamental ao implementar soluções de IA em empresas?', '["Garantir que a IA escolhida seja a mais barata, independentemente de outros fatores.", "Assegurar a transpar\u00eancia, a imparcialidade dos algoritmos e a prote\u00e7\u00e3o da privacidade dos dados.", "Evitar qualquer tipo de feedback humano para n\u00e3o ''contaminar'' o aprendizado da IA.", "Focar apenas nos benef\u00edcios de produtividade sem avaliar impactos sociais."]', 1, 'A ética na IA exige que as soluções sejam transparentes, não discriminatórias, e que a privacidade e segurança dos dados sejam rigorosamente protegidas, além de considerar os impactos sociais.', '2026-03-03T20:27:42.968231+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('01dc30b7-97d7-48c5-a23a-0418b681264d', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'Qual o principal benefício de um chatbot com IA no atendimento ao cliente?', '["Oferecer apenas respostas pr\u00e9-programadas.", "Estar dispon\u00edvel 24/7 para responder a perguntas frequentes e resolver problemas simples, liberando agentes humanos para quest\u00f5es mais complexas.", "Substituir completamente a necessidade de intera\u00e7\u00e3o humana.", "Gerar pedidos fict\u00edcios."]', 1, 'Chatbots com IA podem proporcionar atendimento imediato e contínuo para dúvidas comuns, melhorando a eficiência e a satisfação do cliente, além de otimizar o trabalho da equipe humana.', '2026-03-03T20:27:49.478938+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('26d9d889-fbe6-4bd0-889d-d3a040c59a6c', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'Qual operador é utilizado para realizar a soma entre dois números em programação?', '["-", "*", "+", "/"]', 2, 'O operador ''+'' é o operador aritmético fundamental para realizar a adição de valores numéricos em praticamente todas as linguagens de programação.', '2026-03-11T17:56:38.747966+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b04c3fcf-30cd-4051-af37-964d7b72fed5', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'Em um e-commerce, como a IA pode personalizar a experiência de compra para um visitante?', '["Mostrando o mesmo cat\u00e1logo de produtos para todos os visitantes.", "Recomendando produtos com base no hist\u00f3rico de navega\u00e7\u00e3o, compras anteriores e prefer\u00eancias inferidas do usu\u00e1rio.", "Exibindo an\u00fancios aleat\u00f3rios sem conex\u00e3o com o interesse do cliente.", "Oferecendo um desconto fixo para todos."]', 1, 'A personalização por IA analisa o comportamento individual do usuário para recomendar produtos mais relevantes, aumentando a probabilidade de compra e a satisfação.', '2026-03-03T20:27:49.478938+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b031eb6c-6920-46d6-8ab6-57a94098d355', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'Qual a importância da ''análise de sentimento'' com IA para uma empresa?', '["Ignorar completamente as opini\u00f5es dos clientes.", "Entender as emo\u00e7\u00f5es e opini\u00f5es dos clientes expressas em feedbacks, redes sociais e outras plataformas para identificar pontos fortes e \u00e1reas de melhoria.", "Apenas criar campanhas de marketing gen\u00e9ricas.", "Substituir a necessidade de pesquisa de mercado."]', 1, 'A análise de sentimento permite que as empresas compreendam como os clientes se sentem em relação aos seus produtos ou serviços, possibilitando ajustes estratégicos e melhorias.', '2026-03-03T20:27:49.478938+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b713e096-3137-4482-a1a6-adabae7a4222', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Qual tipo de tarefa de escrita pode ser significativamente agilizado com o uso de IA?', '["Composi\u00e7\u00e3o de sinfonias musicais complexas.", "Reda\u00e7\u00e3o de rascunhos de e-mails, relat\u00f3rios e posts para redes sociais.", "Desenvolvimento de algoritmos de IA para aprendizado profundo.", "Tradu\u00e7\u00e3o simult\u00e2nea de discursos elaborados."]', 1, 'A geração de rascunhos para textos como e-mails, relatórios e posts em mídias sociais é uma das aplicações mais eficazes da IA na escrita.', '2026-03-05T20:18:14.571394+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('736f5ba3-35da-4438-946b-2f38d5ab4b63', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Ao usar IA para criar descrições de produtos, qual é um benefício principal?', '["Garantir que as descri\u00e7\u00f5es sejam sempre mais longas do que o necess\u00e1rio.", "Acelerar o processo de escrita e apresentar ideias de texto.", "Eliminar a necessidade de qualquer revis\u00e3o humana.", "Incluir jarg\u00f5es t\u00e9cnicos complexos incompreens\u00edveis para o p\u00fablico."]', 1, 'As ferramentas de IA podem acelerar significativamente a redação de descrições de produtos e sugerir diferentes abordagens textuais.', '2026-03-05T20:18:14.571394+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2c7f20a0-3870-4a63-a1d1-007a4603992a', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Como a IA pode melhorar a qualidade de um texto escrito por humanos?', '["Introduzindo erros gramaticais para simular imperfei\u00e7\u00f5es.", "Oferecendo sugest\u00f5es de vocabul\u00e1rio, corre\u00e7\u00e3o gramatical e clareza.", "Tornando o texto intencionalmente amb\u00edguo.", "Removendo criatividade e originalidade do conte\u00fado."]', 1, 'A IA pode oferecer sugestões de aprimoramento lexical, correção gramatical e melhorar a fluidez e clareza do texto.', '2026-03-05T20:18:14.571394+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1efddce4-7aa3-4f0f-8975-2fcc064ce071', '089da28e-7c78-427a-8f68-dffd82382e19', 'Qual é o principal objetivo da Inteligência Artificial no contexto da produtividade no trabalho?', '["Substituir completamente os funcion\u00e1rios humanos.", "Automatizar tarefas repetitivas e otimizar processos.", "Criar sistemas de informa\u00e7\u00e3o extremamente complexos.", "Desenvolver novas formas de entretenimento digital."]', 1, 'A IA visa automatizar tarefas repetitivas e otimizar processos, liberando tempo para atividades mais estratégicas e criativas.', '2026-03-05T20:18:14.789715+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c3054fe0-37f4-48d8-b3f7-82a9382bf599', '089da28e-7c78-427a-8f68-dffd82382e19', 'Assinale a alternativa que descreve corretamente um benefício direto da IA para profissionais não técnicos:', '["Necessidade de aprender programa\u00e7\u00e3o avan\u00e7ada.", "Redu\u00e7\u00e3o significativa do tempo gasto em tarefas administrativas.", "Aumento da complexidade dos relat\u00f3rios gerados.", "Depend\u00eancia exclusiva de equipes de TI para qualquer ajuste."]', 1, 'A IA pode reduzir significativamente o tempo gasto em tarefas administrativas, permitindo maior foco em atividades de maior valor.', '2026-03-05T20:18:14.789715+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a60a2f1b-0a12-4a5f-b5c6-1f4b43303121', '089da28e-7c78-427a-8f68-dffd82382e19', 'O que caracteriza uma IA ''fraca'' ou ''estreita''?', '["Capacidade de realizar qualquer tarefa intelectual humana.", "Especializa\u00e7\u00e3o em uma tarefa espec\u00edfica, como reconhecimento de voz.", "Autonomia completa para tomar decis\u00f5es independentes.", "Habilidade de aprender e se adaptar a qualquer situa\u00e7\u00e3o imprevista."]', 1, 'Uma IA fraca (ou estreita) é projetada e treinada para realizar uma tarefa específica.', '2026-03-05T20:18:14.789715+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6de1a2ae-67f5-4cd6-9681-7424dac9346a', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'Qual recurso de IA pode ajudar a organizar e priorizar sua caixa de entrada de e-mails?', '["Um editor de texto avan\u00e7ado.", "Um software de planejamento financeiro.", "Um assistente de e-mail inteligente com filtragem e categoriza\u00e7\u00e3o.", "Um reprodutor de \u00e1udio."]', 2, 'Assistentes de e-mail inteligentes utilizam IA para filtrar, categorizar e priorizar mensagens, otimizando a gestão da caixa de entrada.', '2026-03-05T20:18:14.876372+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('56e417f3-4685-4e06-ac93-7360e452c2a6', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'Como as ferramentas de IA podem facilitar o agendamento de reuniões?', '["Enviando convites manuais para todos os participantes.", "Sugerindo hor\u00e1rios compat\u00edveis com a disponibilidade de todos os envolvidos.", "Necessitando de aprova\u00e7\u00e3o direta do CEO para cada agendamento.", "Ignorando completamente os fusos hor\u00e1rios."]', 1, 'Ferramentas de IA para agendamento analisam calendários e sugerem os melhores horários, considerando a disponibilidade de múltiplos participantes e fusos horários.', '2026-03-05T20:18:14.876372+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('65686d7b-8866-48ed-9777-55993ec9583e', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'Para que serve a capacidade de ''extração de informação'' em documentos utilizando IA?', '["Para converter todos os documentos em formato de imagem.", "Para identificar e recuperar dados espec\u00edficos de grandes volumes de texto.", "Para deletar automaticamente os documentos mais antigos.", "Para iniciar um novo documento em branco."]', 1, 'A extração de informação por IA permite identificar e recuperar dados específicos de documentos, acelerando a análise e o acesso a informações cruciais.', '2026-03-05T20:18:14.876372+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('07ffdcf8-d14e-466a-9e72-f8325b5354d1', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'Qual é o papel da IA na análise de grandes volumes de dados (Big Data)?', '["Apenas armazenar os dados sem processamento.", "Identificar padr\u00f5es, tend\u00eancias e anomalias que seriam dif\u00edceis de detectar manualmente.", "Excluir automaticamente os dados considerados irrelevantes.", "Gerar dados fict\u00edcios para preencher lacunas."]', 1, 'A IA é essencial para processar Big Data, identificando padrões e tendências complexas que auxiliam na compreensão e na tomada de decisão.', '2026-03-05T20:18:37.310033+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4f0cb4dc-629b-4ace-9509-4d99ac1fc597', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'Como a IA pode auxiliar na tomada de decisão estratégica em uma empresa?', '["Fornecendo opini\u00f5es puramente subjetivas sem dados.", "Gerando relat\u00f3rios preditivos com base em an\u00e1lises de dados hist\u00f3ricos e tend\u00eancias.", "Ignorando completamente os resultados de an\u00e1lises.", "Apresentando informa\u00e7\u00f5es desorganizadas sem contexto."]', 1, 'Ao analisar dados e identificar tendências, a IA pode fornecer insights e previsões que embasam decisões estratégicas mais eficazes.', '2026-03-05T20:18:37.310033+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('53d897f3-b21f-497b-bbcc-8b55e2931353', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'O que são ''dashboards inteligentes'' potencializados por IA?', '["Pain\u00e9is est\u00e1ticos com informa\u00e7\u00f5es fixas.", "Interfaces visuais que apresentam dados de forma din\u00e2mica, com insights gerados por IA.", "Sistemas que rodam apenas em computadores de alta performance.", "Ferramentas que exigem programa\u00e7\u00e3o complexa para cada visualiza\u00e7\u00e3o."]', 1, 'Dashboards inteligentes utilizam IA para apresentar dados de maneira interativa, destacando informações relevantes e gerando insights acionáveis automaticamente.', '2026-03-05T20:18:37.310033+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('e0de9704-9931-4a29-a163-1166f1ae544f', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'Como as ferramentas de IA podem auxiliar no planejamento de um projeto?', '["Criando cronogramas fixos sem qualquer flexibilidade.", "Sugerindo a aloca\u00e7\u00e3o de recursos, identificando depend\u00eancias de tarefas e prevendo prazos.", "Excluindo o papel do gerente de projeto.", "Ignorando completamente os imprevistos."]', 1, 'A IA pode auxiliar no planejamento de projetos sugerindo a alocação de recursos, identificando interdependências entre tarefas e estimando prazos mais realistas.', '2026-03-05T20:18:40.863945+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0ace7541-2189-4483-925e-0c85ce01260b', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'De que maneira a IA pode melhorar a gestão de tarefas individuais?', '["Aumentando a quantidade de tarefas n\u00e3o essenciais.", "Priorizando automaticamente tarefas com base em prazos, import\u00e2ncia e carga de trabalho.", "Eliminando a necessidade de definir prioridades.", "Agrupando todas as tarefas em uma \u00fanica categoria."]', 1, 'Ferramentas de IA podem ajudar a priorizar tarefas automaticamente com base em critérios como prazos, importância e carga de trabalho, otimizando a organização pessoal.', '2026-03-05T20:18:40.863945+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('9c273ab6-0304-440f-9e19-9a8d67706d0c', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'Para que serve a ''inteligência preditiva'' na gestão de projetos com IA?', '["Prever apenas os resultados positivos de um projeto.", "Antecipar poss\u00edveis gargalos, riscos ou atrasos no cronograma do projeto.", "Ignorar os riscos e focar apenas nas metas.", "Gerar relat\u00f3rios sobre o que j\u00e1 aconteceu no projeto."]', 1, 'A inteligência preditiva em gestão de projetos com IA visa antecipar potenciais problemas como atrasos, gargalos ou riscos, permitindo ações corretivas proativas.', '2026-03-05T20:18:40.863945+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4b1f1235-56d6-4c92-8704-6629d4230bff', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'Qual é uma preocupação ética importante ao usar IA no ambiente de trabalho?', '["Aumento da efici\u00eancia operacional.", "A possibilidade de vi\u00e9s algor\u00edtmico, levando a decis\u00f5es injustas.", "Simplifica\u00e7\u00e3o de tarefas administrativas.", "A automa\u00e7\u00e3o de processos repetitivos."]', 1, 'O viés algorítmico é uma preocupação ética crucial, pois pode resultar em discriminação e decisões injustas em processos como contratação ou avaliação.', '2026-03-05T20:18:42.1253+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('38dfc7b0-7782-4981-ad2e-a001a47660eb', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'Por que a privacidade de dados é fundamental ao utilizar ferramentas de IA que processam informações?', '["A privacidade de dados n\u00e3o \u00e9 relevante para a IA.", "Para proteger informa\u00e7\u00f5es confidenciais de funcion\u00e1rios e clientes contra vazamentos e uso indevido.", "Para aumentar o volume de dados coletados.", "Para garantir que os dados sejam compartilhados livremente com terceiros."]', 1, 'Proteger a privacidade de dados é essencial para garantir a confidencialidade e a conformidade legal, evitando vazamentos e uso indevido de informações sensíveis.', '2026-03-05T20:18:42.1253+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('52bd194c-b1d9-4204-8aef-0f213fd0fe69', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'O que significa ''viés algorítmico'' em ferramentas de IA?', '["O algoritmo \u00e9 perfeitamente imparcial e nunca falha.", "O algoritmo reflete e amplifica preconceitos presentes nos dados de treinamento.", "O algoritmo \u00e9 projetado para ser menos preciso.", "O algoritmo s\u00f3 funciona com dados de alta qualidade."]', 1, 'Viés algorítmico ocorre quando um algoritmo reflete ou amplifica preconceitos existentes nos dados com os quais foi treinado, levando a resultados discriminatórios.', '2026-03-05T20:18:42.1253+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('30f3b1ea-7703-42ea-92ca-97c7164a431d', '6652a578-9328-4d81-a51a-5cef002b123f', 'Ao selecionar uma ferramenta de IA para sua empresa, qual critério é mais importante considerar?', '["O pre\u00e7o mais baixo dispon\u00edvel no mercado.", "O alinhamento com as necessidades espec\u00edficas do neg\u00f3cio e a facilidade de uso.", "A popularidade da ferramenta sem verificar sua funcionalidade.", "A capacidade de realizar tarefas n\u00e3o relacionadas ao objetivo principal."]', 1, 'É crucial selecionar ferramentas de IA que se alinhem com as necessidades específicas do negócio e que ofereçam uma interface intuitiva para facilitar a adoção e o uso.', '2026-03-05T20:19:09.42259+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('46fb5832-607f-4350-9b3e-c97db6d97cf5', '6652a578-9328-4d81-a51a-5cef002b123f', 'Qual estratégia pode auxiliar na adoção de IA em uma equipe de trabalho?', '["Impor o uso da IA sem treinamento pr\u00e9vio.", "Oferecer treinamento adequado e demonstrar os benef\u00edcios pr\u00e1ticos da ferramenta.", "Ignorar as d\u00favidas e preocupa\u00e7\u00f5es dos membros da equipe.", "Iniciar a implementa\u00e7\u00e3o com as ferramentas mais complexas e menos intuitivas."]', 1, 'Oferecer treinamento abrangente e demonstrar os benefícios tangíveis da IA são estratégias eficazes para promover a adoção e o engajamento da equipe.', '2026-03-05T20:19:09.42259+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('d48c7bb7-ed65-433a-9f59-04b5675b2f65', '6652a578-9328-4d81-a51a-5cef002b123f', 'Quais são as tendências emergentes na aplicação da IA para aumentar a produtividade no trabalho no futuro?', '["Desuso generalizado de ferramentas de IA.", "IA conversacional mais avan\u00e7ada, personaliza\u00e7\u00e3o hiper-inteligente e automa\u00e7\u00e3o colaborativa.", "Foco exclusivo em tarefas manuais e repetitivas.", "Regress\u00e3o para m\u00e9todos de trabalho puramente manuais."]', 1, 'Tendências futuras incluem IA conversacional mais sofisticada, personalização avançada e a automação colaborativa entre humanos e IA.', '2026-03-05T20:19:09.42259+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c8a798c6-8589-4826-af1f-f88feaad85c2', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Qual é a função principal de uma variável em programação?', '["Executar comandos espec\u00edficos.", "Armazenar e referenciar dados em mem\u00f3ria.", "Exibir mensagens na tela do usu\u00e1rio.", "Criar novas fun\u00e7\u00f5es no programa."]', 1, 'Variáveis são como caixas nomeadas em que podemos guardar valores que podem mudar durante a execução do programa.', '2026-03-11T17:37:19.163889+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f4b83c7f-6e10-494f-84ee-54617ae1373e', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Qual tipo de dado é mais apropriado para armazenar o número de alunos em uma turma?', '["Ponto flutuante (float/double)", "Booleano (boolean)", "String", "Inteiro (integer)"]', 3, 'Um número inteiro é o tipo de dado mais adequado, pois a quantidade de alunos deve ser um número completo e sem frações.', '2026-03-11T17:37:19.163889+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('fec1d8ac-9743-4711-a3a7-72371f3facaa', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Qual operador é utilizado para verificar se duas variáveis possuem valores iguais?', '["=", "==", "!=", ">"]', 1, 'O operador de igualdade ''=='' é usado para comparar se os valores de duas variáveis são idênticos.', '2026-03-11T17:37:19.163889+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('be1453f9-fedd-4ccf-af3c-a8bfb3a1cc37', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Qual a finalidade da estrutura condicional ''if'' em programação?', '["Executar um bloco de c\u00f3digo repetidamente.", "Executar um bloco de c\u00f3digo se uma determinada condi\u00e7\u00e3o for verdadeira.", "Definir uma vari\u00e1vel com um valor inicial.", "Chamar uma fun\u00e7\u00e3o externa ao programa."]', 1, 'A estrutura ''if'' permite que o programa tome decisões, executando um conjunto de instruções apenas quando a condição especificada for atendida.', '2026-03-11T17:37:26.092031+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0471aba8-d4da-4c35-8722-39614d299600', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Em que situação a estrutura ''else if'' é mais aplicável?', '["Quando se deseja executar um bloco de c\u00f3digo independentemente de qualquer condi\u00e7\u00e3o.", "Quando se precisa verificar m\u00faltiplas condi\u00e7\u00f5es consecutivas e executar um bloco de c\u00f3digo espec\u00edfico para a primeira condi\u00e7\u00e3o verdadeira encontrada.", "Quando se deseja quebrar um loop de itera\u00e7\u00e3o.", "Para retornar um valor de uma fun\u00e7\u00e3o."]', 1, '''else if'' é usada para testar uma nova condição quando a condição ''if'' anterior foi falsa, permitindo cadeias de decisões.', '2026-03-11T17:37:26.092031+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6dbd09ab-2d63-4e8e-a3f2-20a5c0e4e29e', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Se a condição em um bloco ''if'' for falsa, qual estrutura é executada (se existir)?', '["Um novo bloco ''if''.", "O bloco ''else''.", "O programa termina.", "Um loop ''for''."]', 1, 'Se a condição do ''if'' for falsa e um bloco ''else'' estiver presente, as instruções dentro do bloco ''else'' serão executadas.', '2026-03-11T17:37:26.092031+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b3518ae1-2cb7-47c7-9f95-6a85eda30bc6', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Qual é a principal finalidade da lógica computacional no desenvolvimento de software?', '["Desenvolver interfaces gr\u00e1ficas atraentes.", "Criar algoritmos eficientes para resolver problemas.", "Gerenciar bancos de dados complexos.", "Automatizar tarefas de marketing digital."]', 1, 'A lógica computacional é a base para a criação de instruções claras e sequenciais que um computador pode executar para resolver um problema.', '2026-03-11T17:37:29.363646+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4a6c3713-df77-4105-8ca7-41f00bbf6650', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'O que representa um fluxograma no contexto da lógica computacional?', '["Um c\u00f3digo escrito em linguagem de programa\u00e7\u00e3o.", "Um diagrama visual que representa o fluxo de um processo ou algoritmo.", "Um conjunto de instru\u00e7\u00f5es para o usu\u00e1rio final.", "Um documento de especifica\u00e7\u00e3o t\u00e9cnica do software."]', 1, 'Fluxogramas utilizam símbolos padronizados para ilustrar as etapas e decisões de um algoritmo, facilitando a compreensão do seu funcionamento.', '2026-03-11T17:37:29.363646+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c81d5d9f-bf2b-4935-8c77-2de709ac6dac', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Em relação ao pseudocódigo, qual das afirmações é mais precisa?', '["\u00c9 uma linguagem de programa\u00e7\u00e3o formal com sintaxe r\u00edgida.", "\u00c9 uma descri\u00e7\u00e3o textual de um algoritmo, mais pr\u00f3xima da linguagem natural.", "\u00c9 uma representa\u00e7\u00e3o gr\u00e1fica exclusiva para algoritmos complexos.", "\u00c9 utilizado apenas para a fase de testes de um programa."]', 1, 'O pseudocódigo é uma forma de descrever um algoritmo usando uma linguagem informal, mas estruturada, que se assemelha à linguagem natural, antes de ser traduzido para uma linguagem de programação real.', '2026-03-11T17:37:29.363646+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c7ecdfb7-9bbc-43ef-99f0-72d8cbfc3a08', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Qual loop é geralmente preferível quando se sabe o número exato de iterações que o código deve executar?', '["Loop ''while''.", "Loop ''for''.", "Loop ''if''.", "Loop ''else''."]', 1, 'O loop ''for'' é mais adequado quando o número de repetições é conhecido antecipadamente, pois ele gerencia o contador e a condição de parada de forma integrada.', '2026-03-11T17:37:59.439461+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1c03e742-5434-4b42-a167-d806f44e7718', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Em qual situação o loop ''while'' é mais vantajoso?', '["Quando o n\u00famero de itera\u00e7\u00f5es \u00e9 fixo e conhecido.", "Quando o loop deve continuar executando enquanto uma condi\u00e7\u00e3o espec\u00edfica for verdadeira, e o n\u00famero de itera\u00e7\u00f5es n\u00e3o \u00e9 predeterminado.", "Para executar um bloco de c\u00f3digo apenas uma vez.", "Para definir constantes no programa."]', 1, 'O loop ''while'' é ideal para situações onde a repetição depende de uma condição que pode ou não ser satisfeita em um número fixo de vezes.', '2026-03-11T17:37:59.439461+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('718a21d9-9251-4572-8ddb-37a9f94a7cf3', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Qual é o risco de se criar um loop sem uma condição de parada adequada?', '["O programa pode terminar prematuramente.", "O programa pode entrar em um loop infinito, travando o sistema.", "As vari\u00e1veis podem ser sobrescritas.", "Apenas uma itera\u00e7\u00e3o ser\u00e1 executada."]', 1, 'Um loop sem uma condição de parada clara ou que não é atingida fará com que o loop se execute indefinidamente, consumindo recursos e travando a aplicação.', '2026-03-11T17:37:59.439461+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a4be79d4-87a5-4871-8e96-41ff1d408a24', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'O que distingue um ''achado de auditoria'' em relação a uma simples observação?', '["Um achado \u00e9 apenas uma falha identificada.", "Um achado \u00e9 uma compara\u00e7\u00e3o documentada entre o que ''\u00e9'' e o que ''deveria ser'', com suas causas e efeitos.", "Um achado \u00e9 uma sugest\u00e3o de melhoria da gest\u00e3o.", "Um achado \u00e9 sempre uma irregularidade legal."]', 1, 'Um achado de auditoria é uma constatação completa, estruturada com base na comparação entre a situação atual observada e o critério esperado, explicando as causas dos desvios e seus efeitos.', '2026-03-12T20:32:21.14296+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c02c6503-c578-4444-951b-5dccf2d86131', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'Qual dos seguintes elementos é crucial para a formulação de uma recomendação de auditoria eficaz?', '["Ser gen\u00e9rica e aplic\u00e1vel a diversas entidades.", "Ser vaga para permitir flexibilidade na implementa\u00e7\u00e3o.", "Ser clara, objetiva, fact\u00edvel, endere\u00e7ar a causa raiz e visar \u00e0 melhoria do desempenho.", "Ser estritamente legalista, sem considerar a realidade operacional."]', 2, 'Recomendações eficazes devem ser específicas, alcançáveis, relevantes e temporizáveis, focando em resolver a causa raiz do problema e otimizar os resultados.', '2026-03-12T20:32:21.14296+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('bfe6d038-9441-4fdf-89ac-7e99120c664d', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'A estrutura de um achado de auditoria operacional geralmente inclui quais componentes?', '["Apenas a descri\u00e7\u00e3o da irregularidade.", "Condi\u00e7\u00e3o, Crit\u00e9rio, Causa e Efeito.", "Nome do auditor, data e hora da constata\u00e7\u00e3o.", "Valor do preju\u00edzo e nome do respons\u00e1vel."]', 1, 'A estrutura ''4 Cs'' – Condição (o que foi encontrado), Critério (o que deveria ser), Causa (por que aconteceu) e Efeito (consequência) – é fundamental para a elaboração de um achado completo e compreensível.', '2026-03-12T20:32:21.14296+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('109437bf-6da6-4d3d-8a5c-be5303f1cd2c', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Qual a principal característica de um relatório de auditoria operacional de alta qualidade?', '["Ser extenso e conter todos os detalhes da auditoria.", "Ser subjetivo, reflexo da opini\u00e3o do auditor.", "Ser objetivo, claro, conciso, convincente e construtivo, fornecendo informa\u00e7\u00f5es \u00fateis para a gest\u00e3o.", "Ser escrito em linguagem t\u00e9cnica e complexa para demonstrar rigor."]', 2, 'Um relatório de qualidade é aquele que comunica as informações de forma eficaz, de modo que os achados e recomendações sejam compreendidos e possam ser utilizados para aprimorar a gestão.', '2026-03-12T20:32:24.600816+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('ddb3b772-3577-4b97-b919-5ca4cfedc049', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'O que significa a fase de ''contraditório'' na auditoria operacional?', '["Confronto entre os auditores da equipe.", "Momento em que a entidade auditada tem a oportunidade de analisar os achados e recomenda\u00e7\u00f5es preliminares e apresentar sua manifesta\u00e7\u00e3o antes da finaliza\u00e7\u00e3o do relat\u00f3rio.", "Processo de revis\u00e3o do relat\u00f3rio por um auditor externo.", "Negocia\u00e7\u00e3o de prazos para a implementa\u00e7\u00e3o das recomenda\u00e7\u00f5es."]', 1, 'O contraditório é um princípio fundamental que garante o direito à defesa e a veracidade das informações, permitindo que a entidade auditada se manifeste sobre o que foi constatado, antes do relatório final.', '2026-03-12T20:32:24.600816+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('3bd74c50-4f8e-4706-9c06-823e21720045', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Qual a principal utilidade de criar uma função em um programa?', '["Para armazenar dados temporariamente.", "Para encapsular um bloco de c\u00f3digo que realiza uma tarefa espec\u00edfica e reutiliz\u00e1vel.", "Para definir a velocidade de execu\u00e7\u00e3o do programa.", "Para gerenciar a interface do usu\u00e1rio."]', 1, 'Funções permitem que você agrupe código em unidades lógicas e nomeadas que podem ser chamadas várias vezes, evitando repetição e organizando o código.', '2026-03-11T17:38:05.992607+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('fcb9925c-5409-42c4-8cea-9133bddebb5d', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Qual a diferença entre uma função que retorna um valor e um procedimento (ou função que não retorna valor)?', '["Um procedimento \u00e9 sempre executado antes de uma fun\u00e7\u00e3o que retorna valor.", "Uma fun\u00e7\u00e3o que retorna valor produz um resultado que pode ser usado em outras partes do programa, enquanto um procedimento apenas executa a\u00e7\u00f5es sem retornar um valor expl\u00edcito.", "Um procedimento aceita par\u00e2metros, mas uma fun\u00e7\u00e3o de retorno n\u00e3o.", "N\u00e3o h\u00e1 diferen\u00e7a fundamental; s\u00e3o sin\u00f4nimos."]', 1, 'Funções que retornam valores são usadas para calcular ou obter algo que será utilizado posteriormente, enquanto procedimentos focam em realizar ''ações'' ou ''efeitos colaterais''.', '2026-03-11T17:38:05.992607+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('528d8038-96e8-4460-a20f-2498cc95084b', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'O que são parâmetros de uma função?', '["Os valores que a fun\u00e7\u00e3o retorna.", "Vari\u00e1veis internas que a fun\u00e7\u00e3o utiliza.", "Dados de entrada que a fun\u00e7\u00e3o recebe para processar.", "O nome da fun\u00e7\u00e3o."]', 2, 'Parâmetros são variáveis que a função aceita como entrada. Eles permitem que a função opere sobre diferentes valores a cada chamada.', '2026-03-11T17:38:05.992607+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('70fcc3cd-96a4-4d5c-a10a-c3ebca2cce2a', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Qual a finalidade do monitoramento das recomendações de auditoria?', '["Determinar novas \u00e1reas para futuras auditorias.", "Verificar a implementa\u00e7\u00e3o das recomenda\u00e7\u00f5es e seus resultados, garantindo que as melhorias planejadas ocorreram.", "Reavaliar o desempenho da equipe de auditoria.", "Calcular multas e penalidades aplic\u00e1veis."]', 1, 'O monitoramento é essencial para assegurar que as ações corretivas foram tomadas e que os objetivos de melhoria foram atingidos, fechando o ciclo da auditoria e agregando valor à organização.', '2026-03-12T20:32:24.600816+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1716339a-8e5e-45c4-91f0-bd657ce71005', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'O que é um array em ciência da computação?', '["Uma estrutura para armazenar dados em formato de \u00e1rvore.", "Uma cole\u00e7\u00e3o de elementos do mesmo tipo, acessados por um \u00edndice.", "Um \u00fanico valor de dados.", "Um conjunto de fun\u00e7\u00f5es que operam em dados."]', 1, 'Um array é um tipo de estrutura de dados que armazena uma coleção de itens (geralmente do mesmo tipo) em posições sequenciais numeradas (índices).', '2026-03-11T17:38:07.075953+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('30fefcde-1656-4c41-a455-6c28420e6532', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'Como os elementos de um array são geralmente acessados?', '["Por meio de um nome \u00fanico para cada elemento.", "Pelo seu valor.", "Por um \u00edndice num\u00e9rico que representa sua posi\u00e7\u00e3o.", "Utilizando uma chave associativa."]', 2, 'Os elementos em um array são acessados através de um índice numérico, que começa em 0 para o primeiro elemento.', '2026-03-11T17:38:07.075953+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2451e47c-e778-4147-89b6-550c8dd46f2b', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'Qual a principal diferença entre um array de tamanho fixo e uma lista (ou array dinâmico)?', '["Arrays de tamanho fixo permitem a inser\u00e7\u00e3o de diferentes tipos de dados.", "Listas (array din\u00e2mico) podem crescer ou diminuir em tamanho durante a execu\u00e7\u00e3o do programa, enquanto arrays tradicionais t\u00eam um tamanho fixo.", "Arrays de tamanho fixo podem ser percorridos mais rapidamente.", "Listas s\u00e3o mais f\u00e1ceis de visualizar em fluxogramas."]', 1, 'Arrays tradicionais possuem um tamanho pré-definido na criação, enquanto listas são mais flexíveis e podem ser redimensionadas conforme a necessidade.', '2026-03-11T17:38:07.075953+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('cd068508-9b47-423b-a2e3-34fb31a70db9', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Por que a indentação correta do código é considerada uma boa prática?', '["Ela acelera a execu\u00e7\u00e3o do programa.", "Ela ajuda a visualizar a estrutura l\u00f3gica do c\u00f3digo, facilitando a leitura e a identifica\u00e7\u00e3o de blocos.", "Ela remove coment\u00e1rios automaticamente.", "Ela \u00e9 obrigat\u00f3ria em todas as linguagens de programa\u00e7\u00e3o."]', 1, 'A indentação alinha visualmente blocos de código (como os de ''if'', ''for'', funções), tornando a estrutura do programa mais clara e fácil de seguir.', '2026-03-11T17:38:59.721366+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4f844a87-0b9f-40af-a132-2bce58fde203', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Qual o principal objetivo de utilizar comentários no código?', '["Para enganar outros programadores.", "Para explicar a l\u00f3gica complexa ou a inten\u00e7\u00e3o por tr\u00e1s de certas partes do c\u00f3digo, auxiliando na manuten\u00e7\u00e3o e compreens\u00e3o.", "Para reduzir o tamanho do arquivo do c\u00f3digo-fonte.", "Para garantir que o c\u00f3digo seja executado mais rapidamente."]', 1, 'Comentários servem como notas explicativas para humanos, ajudando a entender o ''porquê'' e o ''como'' de partes específicas do código.', '2026-03-11T17:38:59.721366+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0ded411a-59b0-469a-8f76-cb0e140a7ee1', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Qual das seguintes convenções de nomenclatura é geralmente preferível para variáveis?', '["Nomes curtos e com uma \u00fanica letra (ex: ''a'', ''b'').", "Nomes totalmente em mai\u00fasculas (ex: ''NOMEDAVARIAVEL'').", "Nomes descritivos que refletem o prop\u00f3sito da vari\u00e1vel (ex: ''contadorDeItens'').", "Nomes com caracteres especiais e n\u00fameros no in\u00edcio."]', 2, 'Nomes descritivos e significativos para variáveis e funções facilitam enormemente a compreensão do código por você mesmo e por outros desenvolvedores.', '2026-03-11T17:38:59.721366+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('152d09ce-2706-48c3-89b5-3b6d5f84408f', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Qual a importância de aplicar os conceitos em um projeto prático?', '["Apenas para fins de avalia\u00e7\u00e3o formal.", "Para consolidar o aprendizado, identificar lacunas e desenvolver habilidades de resolu\u00e7\u00e3o de problemas reais.", "Para provar a capacidade de memoriza\u00e7\u00e3o.", "Para aprender a usar ferramentas de edi\u00e7\u00e3o de texto."]', 1, 'Projetos práticos são cruciais porque unem a teoria à prática, permitindo que os alunos enfrentem desafios reais e apliquem o conhecimento de forma integrada.', '2026-03-11T17:39:01.620666+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4302682d-0fc4-4cc7-a156-ca7f3b36d6fc', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Quais tipos de projetos simples são recomendados para iniciantes após este curso?', '["Desenvolvimento de sistemas operacionais complexos.", "Aplica\u00e7\u00f5es web b\u00e1sicas, calculadoras, jogos de adivinha\u00e7\u00e3o ou gerenciadores de tarefas simples.", "Ferramentas de intelig\u00eancia artificial avan\u00e7ada.", "Edi\u00e7\u00e3o de v\u00eddeos e anima\u00e7\u00f5es em 3D."]', 1, 'Projetos menores, como calculadoras, jogos simples ou gerenciadores de lista, permitem que os iniciantes apliquem conceitos de forma controlada e construam confiança.', '2026-03-11T17:39:01.620666+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2520faaa-9e2c-4061-93df-01a955afbc30', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Para continuar aprendendo programação, qual das seguintes sugestões é mais valiosa?', '["Parar de codificar ap\u00f3s este curso.", "Participar de comunidades de desenvolvedores, ler documenta\u00e7\u00e3o e continuar praticando com novos desafios.", "Depender exclusivamente de tutoriais de v\u00eddeo para todas as tarefas.", "Focar apenas em teoria e nunca escrever c\u00f3digo."]', 1, 'A prática contínua, a colaboração com outros desenvolvedores e a busca ativa por conhecimento são fundamentais para o crescimento na área de programação.', '2026-03-11T17:39:01.620666+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('7e425449-a18f-41a8-a9e5-996837e1c23c', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Qual a principal característica de um algoritmo?', '["Ser amb\u00edguo e deixar margem para interpreta\u00e7\u00e3o.", "Ser executado em tempo infinito.", "Ser um conjunto finito e ordenado de instru\u00e7\u00f5es para resolver um problema.", "N\u00e3o necessitar de entrada ou sa\u00edda de dados."]', 2, 'Um algoritmo é uma sequência finita e bem definida de instruções que, ao serem executadas, produzem um resultado ou resolvem um problema específico.', '2026-03-11T17:46:59.933113+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4abdbab7-523f-4001-b4c9-29cfe4fb08d0', '8e92b920-5447-4356-9e40-294db76d7fe6', 'O que um fluxograma representa em um algoritmo?', '["Somente o resultado final do processamento.", "A representa\u00e7\u00e3o gr\u00e1fica dos passos e decis\u00f5es do algoritmo.", "Uma lista de vari\u00e1veis utilizadas.", "O tempo de execu\u00e7\u00e3o do programa."]', 1, 'O fluxograma é uma ferramenta visual que utiliza símbolos padronizados para ilustrar o fluxo de controle e as operações de um algoritmo.', '2026-03-11T17:46:59.933113+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('db815183-d0b4-41e4-b6c7-67378782e253', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Em pseudocódigo, qual é o objetivo da instrução "ENQUANTO"?', '["Executar um bloco de c\u00f3digo uma \u00fanica vez.", "Pular para uma parte espec\u00edfica do c\u00f3digo.", "Repetir um bloco de c\u00f3digo enquanto uma condi\u00e7\u00e3o for verdadeira.", "Tomar uma decis\u00e3o com base em m\u00faltiplos crit\u00e9rios."]', 2, 'A instrução "ENQUANTO" (ou WHILE em inglês) é utilizada em pseudocódigo para criar laços de repetição que continuam enquanto a condição especificada permanecer verdadeira.', '2026-03-11T17:46:59.933113+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('98171e2f-ac02-4d3a-b10a-4af2d0e72666', '511afd44-edc1-487e-bd88-d4399ec3351b', 'Qual tipo de dado é geralmente utilizado para armazenar números inteiros sem casas decimais?', '["Float", "String", "Boolean", "Integer"]', 3, 'O tipo de dado ''Integer'' é projetado especificamente para armazenar números inteiros.', '2026-03-11T17:47:00.247112+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('11223894-4644-4f5d-b26e-5d56290a7418', '511afd44-edc1-487e-bd88-d4399ec3351b', 'O que o operador de atribuição ''='' faz em programação?', '["Compara dois valores.", "Realiza uma opera\u00e7\u00e3o de adi\u00e7\u00e3o.", "Atribui um valor a uma vari\u00e1vel.", "Verifica se dois valores s\u00e3o iguais."]', 2, 'O operador ''='' é o operador de atribuição, usado para dar um valor a uma variável.', '2026-03-11T17:47:00.247112+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a6d926b7-07db-47b7-88e9-6e6c4850502f', '511afd44-edc1-487e-bd88-d4399ec3351b', 'Qual operador lógico retorna verdadeiro apenas se ambas as condições forem verdadeiras?', '["OU (OR)", "N\u00c3O (NOT)", "E (AND)", "XOR"]', 2, 'O operador lógico ''E'' (AND) retorna verdadeiro somente quando todas as condições conectadas por ele forem verdadeiras.', '2026-03-11T17:47:00.247112+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b657f1e0-9341-4202-b831-50feb0abd1a3', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Em uma estrutura condicional ''if'', qual a condição para que o bloco de código dentro dela seja executado?', '["A condi\u00e7\u00e3o deve ser falsa.", "A condi\u00e7\u00e3o deve ser verdadeira.", "N\u00e3o h\u00e1 necessidade de condi\u00e7\u00e3o.", "A condi\u00e7\u00e3o deve ser amb\u00edgua."]', 1, 'O bloco de código dentro de um ''if'' é executado somente se a condição associada a ele for avaliada como verdadeira.', '2026-03-11T17:47:00.317035+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('050df968-fb17-4ab4-81de-544a759068d2', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Qual é o propósito da cláusula ''else'' em uma estrutura ''if-else''?', '["Executar um c\u00f3digo adicional se a condi\u00e7\u00e3o principal for verdadeira.", "Executar um c\u00f3digo alternativo se a condi\u00e7\u00e3o principal for falsa.", "Encadear m\u00faltiplas condi\u00e7\u00f5es de verifica\u00e7\u00e3o.", "Definir um valor padr\u00e3o para uma vari\u00e1vel."]', 1, 'A cláusula ''else'' em uma estrutura ''if-else'' executa um bloco de código distinto quando a condição do ''if'' é falsa.', '2026-03-11T17:47:00.317035+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1dcba15c-984d-4a72-8393-e4e15b2c94d6', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Quando é apropriado usar a estrutura ''if-else if-else''?', '["Quando apenas uma condi\u00e7\u00e3o precisa ser verificada.", "Quando v\u00e1rias condi\u00e7\u00f5es independentes precisam ser verificadas.", "Quando precisamos de uma cadeia de verifica\u00e7\u00f5es condicionais, onde apenas um bloco de c\u00f3digo ser\u00e1 executado.", "Para declarar m\u00faltiplas vari\u00e1veis."]', 2, 'A estrutura ''if-else if-else'' é ideal para verificar uma série de condições em ordem e executar o bloco correspondente à primeira condição verdadeira encontrada.', '2026-03-11T17:47:00.317035+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a791f8b7-5605-49d2-85fd-86387ceb0668', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Qual tipo de loop é mais adequado quando o número de iterações é conhecido antecipadamente?', '["Loop While", "Loop Do-While", "Loop For", "Loop Infinito"]', 2, 'O loop ''For'' é ideal quando se sabe exatamente quantas vezes o bloco de código precisa ser repetido, pois ele gerencia o contador e a condição de parada.', '2026-03-11T17:47:32.61753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6261a6ce-2362-4c92-afd8-45ab12f27e87', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Em um loop ''while'', qual é a condição para que ele continue executando?', '["A condi\u00e7\u00e3o se torna falsa.", "A condi\u00e7\u00e3o permanece verdadeira.", "Um contador atinge um valor espec\u00edfico.", "O usu\u00e1rio interage com o programa."]', 1, 'Um loop ''while'' continua executando o bloco de código enquanto a condição especificada for avaliada como verdadeira.', '2026-03-11T17:47:32.61753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('e2651b27-d370-4aad-9b5a-e2252c3ff269', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'O que pode acontecer se a condição de parada de um loop nunca for atingida?', '["O programa finalizar\u00e1 rapidamente.", "O loop terminar\u00e1 ap\u00f3s a primeira itera\u00e7\u00e3o.", "Ocorrer\u00e1 um ''loop infinito'', travando o programa.", "O loop se transformar\u00e1 em um loop ''for''."]', 2, 'Se a condição de um loop nunca se tornar falsa (para ''while'' e ''do-while'') ou a condição de continuação nunca se tornar falsa (para ''for''), o programa entrará em um loop infinito, consumindo recursos e potencialmente travando.', '2026-03-11T17:47:32.61753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('15f070a2-52c4-465b-8616-cad9630f6f56', 'f59c5f35-c986-4791-97ff-1681c531742a', 'O que é um array em programação?', '["Um \u00fanico valor armazenado na mem\u00f3ria.", "Uma cole\u00e7\u00e3o de elementos do mesmo tipo, acessados por um \u00edndice.", "Uma fun\u00e7\u00e3o que realiza c\u00e1lculos complexos.", "Um tipo de dado booleano."]', 1, 'Um array é uma estrutura de dados que armazena uma coleção de elementos, geralmente do mesmo tipo, em posições contíguas de memória e acessíveis por um índice numérico.', '2026-03-11T17:47:39.292077+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c328ac79-377b-4964-a12c-cde260e70a5e', 'f59c5f35-c986-4791-97ff-1681c531742a', 'Como os índices de um array são geralmente numerados?', '["Come\u00e7ando do 1.", "Come\u00e7ando do 0.", "Aleatoriamente.", "Depende do tipo de dado."]', 1, 'Na maioria das linguagens de programação, os índices de um array começam em 0. O primeiro elemento está no índice 0, o segundo no índice 1, e assim por diante.', '2026-03-11T17:47:39.292077+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b0fbcca0-0e00-4243-baf5-7c052704e4f7', 'f59c5f35-c986-4791-97ff-1681c531742a', 'Qual a principal vantagem de usar uma lista (dinâmica) em vez de um array fixo?', '["Listas s\u00e3o sempre mais r\u00e1pidas para acessar elementos.", "Listas podem crescer ou encolher dinamicamente conforme a necessidade.", "Listas garantem que todos os elementos sejam do mesmo tipo estritamente.", "Listas requerem menos mem\u00f3ria que arrays."]', 1, 'A principal vantagem das listas dinâmicas é a sua flexibilidade para adicionar ou remover elementos, ajustando automaticamente o tamanho, algo que arrays de tamanho fixo não permitem.', '2026-03-11T17:47:39.292077+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('15dccce5-e62c-4965-8e4b-cfeb847886e6', 'b8fa6c5c-cc45-483f-a272-202ac174bd68', 'Qual é a função principal do comando `print()` em Python?', '["A) Ler dados do usu\u00e1rio.", "B) Exibir mensagens no console.", "C) Declarar uma vari\u00e1vel.", "D) Realizar opera\u00e7\u00f5es matem\u00e1ticas."]', 0, NULL, '2026-03-12T22:45:05.110188+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('05f32f72-e527-4fa6-9879-3032e8ecfe91', 'b8fa6c5c-cc45-483f-a272-202ac174bd68', 'Qual operador é usado para verificar se dois valores são iguais em Python?', '["A) =", "B) ==", "C) !=", "D) >="]', 0, NULL, '2026-03-12T22:45:05.110188+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0a35277e-b197-4574-9b39-a5dc4d2e7de0', 'b8fa6c5c-cc45-483f-a272-202ac174bd68', 'Um ''loop for'' é mais adequado para qual cenário?', '["A) Quando voc\u00ea n\u00e3o sabe quantas vezes precisa repetir uma a\u00e7\u00e3o.", "B) Quando voc\u00ea precisa repetir uma a\u00e7\u00e3o por um n\u00famero fixo de vezes ou iterar sobre uma sequ\u00eancia.", "C) Para tomar decis\u00f5es baseadas em condi\u00e7\u00f5es.", "D) Para definir uma fun\u00e7\u00e3o."]', 0, NULL, '2026-03-12T22:45:05.110188+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('9503de60-d31c-4f50-a3ed-113babbadf1e', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'Qual é o principal benefício de usar funções em um programa?', '["Aumentar a complexidade do c\u00f3digo.", "Diminuir a velocidade de execu\u00e7\u00e3o.", "Promover a reutiliza\u00e7\u00e3o de c\u00f3digo e modularidade.", "Eliminar a necessidade de testes."]', 2, 'Funções permitem encapsular blocos de código que realizam tarefas específicas, facilitando a reutilização e a organização do programa, o que é fundamental para a modularidade e a eficiência.', '2026-03-11T17:47:42.018467+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1a94500a-2dae-44d5-a093-c20704eb939d', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'O que são ''parâmetros de uma função''?', '["Os valores que a fun\u00e7\u00e3o retorna.", "Vari\u00e1veis que recebem valores quando a fun\u00e7\u00e3o \u00e9 chamada, para serem usadas dentro dela.", "O nome \u00fanico da fun\u00e7\u00e3o.", "O bloco de c\u00f3digo que a fun\u00e7\u00e3o executa."]', 1, 'Parâmetros são as variáveis definidas na declaração de uma função que recebem os valores passados como argumentos quando a função é invocada, permitindo que ela opere com dados diferentes a cada chamada.', '2026-03-11T17:47:42.018467+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a30efe7f-7bcc-49dd-8174-4c50338d62c2', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'Qual a importância da instrução ''return'' em uma função?', '["Para iniciar a execu\u00e7\u00e3o da fun\u00e7\u00e3o.", "Para indicar o fim da fun\u00e7\u00e3o e opcionalmente enviar um valor de volta para onde foi chamada.", "Para declarar novas vari\u00e1veis dentro da fun\u00e7\u00e3o.", "Para pausar a execu\u00e7\u00e3o da fun\u00e7\u00e3o."]', 1, 'A instrução ''return'' encerra a execução da função e pode, opcionalmente, retornar um valor para o ponto de onde a função foi chamada. Funções que não possuem um ''return'' explícito geralmente retornam um valor padrão (como ''undefined'' ou ''null'').', '2026-03-11T17:47:42.018467+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4492a9d3-d9e9-43ad-9ccd-885ad397d3f9', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'Qual a importância da identação consistente em um código?', '["Aumentar a velocidade de execu\u00e7\u00e3o.", "Tornar o c\u00f3digo visualmente mais organizado e f\u00e1cil de entender a estrutura.", "Definir o tipo de dado das vari\u00e1veis.", "Remover coment\u00e1rios desnecess\u00e1rios."]', 1, 'A identação correta e consistente (uso de espaços ou tabulações para alinhar blocos de código) é crucial para a legibilidade, pois ajuda a visualizar a estrutura hierárquica do código, como laços e condicionais.', '2026-03-11T17:48:22.464244+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('9a249683-0635-4a93-937d-90658ab436c3', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'O que caracteriza um nome de variável e função ''descritivo''?', '["Nomes curtos que economizam digita\u00e7\u00e3o.", "Nomes que n\u00e3o revelam o prop\u00f3sito da vari\u00e1vel ou fun\u00e7\u00e3o.", "Nomes que explicam claramente o que a vari\u00e1vel armazena ou o que a fun\u00e7\u00e3o faz.", "Nomes com caracteres especiais e n\u00fameros."]', 2, 'Nomes descritivos usam palavras que indicam claramente a finalidade da variável, função ou classe, ajudando outros desenvolvedores (e você mesmo no futuro) a entenderem o código rapidamente.', '2026-03-11T17:48:22.464244+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('eed89f0e-6816-44d3-97f5-1074d6fbae2d', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'Qual é o propósito principal dos comentários em um código fonte?', '["Aumentar o tamanho do arquivo para parecer mais profissional.", "Explicar partes complexas, a inten\u00e7\u00e3o do c\u00f3digo ou informa\u00e7\u00f5es importantes que n\u00e3o s\u00e3o \u00f3bvias.", "Substituir a necessidade de nomes descritivos.", "Indicar o tipo de dados que uma vari\u00e1vel armazena."]', 1, 'Comentários servem para adicionar notas explicativas ao código fonte, tornando-o mais compreensível. Devem explicar o ''porquê'' e o ''como'' de partes não triviais, não duplicar o que o código já expressa claramente.', '2026-03-11T17:48:22.464244+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('293aff49-e226-4ee5-8baa-83399826f8af', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'Qual é a primeira etapa fundamental no desenvolvimento de qualquer projeto de software?', '["Escrever todo o c\u00f3digo o mais r\u00e1pido poss\u00edvel.", "Testar exaustivamente antes de projetar.", "Planejar e definir claramente os requisitos e o escopo do projeto.", "Escolher a linguagem de programa\u00e7\u00e3o mais moderna."]', 2, 'Antes de escrever qualquer linha de código, é essencial um planejamento cuidadoso, que inclui a definição dos objetivos, requisitos e o escopo do projeto, para garantir que a solução atenda às necessidades.', '2026-03-11T17:48:30.164654+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('71ecb56a-950d-40bf-bec7-8cb2de480e06', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'O que significa ''depurar'' um programa?', '["Escrever o c\u00f3digo do zero.", "Identificar e corrigir erros (bugs) no c\u00f3digo.", "Adicionar novas funcionalidades.", "Otimizar o desempenho."]', 1, 'Depurar um programa é o processo de encontrar, analisar e corrigir defeitos (bugs) que impedem o programa de funcionar corretamente ou de atingir seus objetivos sem erros.', '2026-03-11T17:48:30.164654+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4526bdd5-decf-4c70-8865-46b9c19fa216', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'Qual o papel dos testes no ciclo de desenvolvimento de software?', '["Apenas para verificar se o programa trava.", "Para garantir que o software funcione como esperado, identificar bugs e validar requisitos.", "Para decorar o c\u00f3digo com mais informa\u00e7\u00f5es.", "Para tornar o programa mais lento intencionalmente."]', 1, 'Testes são essenciais para verificar a correção, a confiabilidade e a qualidade do software. Eles ajudam a garantir que cada parte do programa funcione conforme planejado e a identificar bugs precocemente.', '2026-03-11T17:48:30.164654+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('dbb23217-8f2c-4e54-ab65-4988de1d237e', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'Qual a principal característica de um algoritmo?', '["Ser amb\u00edguo e n\u00e3o ter fim definido.", "Ser finito, preciso e ter uma s\u00e9rie de passos para resolver um problema.", "Depender exclusivamente da velocidade do hardware.", "Ser escrito apenas em linguagem de m\u00e1quina."]', 1, 'Um algoritmo é uma sequência finita e bem definida de instruções que, quando executada, resolve um problema específico.', '2026-03-11T17:55:54.874713+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('372da8e3-6206-454c-83a1-fd21d3e26eeb', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'O que um fluxograma representa em programação?', '["O c\u00f3digo fonte completo de um programa.", "A arquitetura de hardware do computador.", "A representa\u00e7\u00e3o visual de um algoritmo, mostrando o fluxo de controle.", "O resultado final da execu\u00e7\u00e3o de um programa."]', 2, 'Um fluxograma utiliza símbolos padronizados para ilustrar graficamente os passos e a sequência de operações de um algoritmo.', '2026-03-11T17:55:54.874713+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1f1fca9d-5eea-45d6-b6f4-b4177586653d', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'Qual a importância da etapa de ''definição do problema'' em um projeto de programação?', '["\u00c9 irrelevante, pois o programador pode descobrir a solu\u00e7\u00e3o durante a codifica\u00e7\u00e3o.", "Permite antecipar falhas no hardware.", "Garante que a solu\u00e7\u00e3o desenvolvida atenda exatamente \u00e0s necessidades.", "Ajuda a escolher a linguagem de programa\u00e7\u00e3o mais avan\u00e7ada."]', 2, 'Uma definição clara do problema é crucial para garantir que o desenvolvimento do software seja direcionado e eficaz, atendendo aos requisitos.', '2026-03-11T17:55:54.874713+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('ba2abd4a-77bd-48e0-a443-c2ed082e03e8', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'Qual a principal diferença entre linguagens de alto nível e de baixo nível?', '["Linguagens de alto n\u00edvel s\u00e3o mais pr\u00f3ximas do hardware, enquanto de baixo n\u00edvel s\u00e3o mais pr\u00f3ximas da linguagem humana.", "Linguagens de alto n\u00edvel s\u00e3o mais pr\u00f3ximas da linguagem humana, enquanto de baixo n\u00edvel s\u00e3o mais pr\u00f3ximas do hardware.", "Linguagens de alto n\u00edvel exigem compiladores, enquanto de baixo n\u00edvel n\u00e3o.", "N\u00e3o existe diferen\u00e7a significativa entre elas."]', 1, 'Linguagens de alto nível usam vocabulário mais familiar aos humanos e abstraem detalhes de hardware, enquanto linguagens de baixo nível (como Assembly) interagem diretamente com a arquitetura do processador.', '2026-03-11T17:55:55.880925+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('46c26d4c-ea65-4b7c-a9bc-0babb020b3a5', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'O que o termo ''sintaxe'' significa no contexto de linguagens de programação?', '["A l\u00f3gica por tr\u00e1s da execu\u00e7\u00e3o do c\u00f3digo.", "A estrutura de dados utilizada no programa.", "As regras gramaticais e a ordem correta em que os comandos devem ser escritos.", "O n\u00famero de linhas de c\u00f3digo escritas."]', 2, 'Sintaxe refere-se ao conjunto de regras que definem a combinação válida de símbolos e palavras-chave para formar instruções em uma linguagem de programação.', '2026-03-11T17:55:55.880925+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('871ac20f-f1e0-4950-827a-cae4128cfdaa', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'Qual o objetivo principal de um compilador?', '["Executar o c\u00f3digo diretamente.", "Traduzir o c\u00f3digo-fonte escrito em linguagem de alto n\u00edvel para c\u00f3digo de m\u00e1quina ou um formato intermedi\u00e1rio execut\u00e1vel.", "Gerar documenta\u00e7\u00e3o para o c\u00f3digo.", "Realizar a depura\u00e7\u00e3o do programa."]', 1, 'O compilador é um programa que converte o código-fonte, escrito em uma linguagem de programação de alto nível, em instruções que o processador do computador pode entender e executar.', '2026-03-11T17:55:55.880925+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('577c36ce-52fa-4298-bbb6-a75bc25d0043', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'Qual a diferença principal entre uma variável e uma constante?', '["Vari\u00e1veis podem ser alteradas durante a execu\u00e7\u00e3o, enquanto constantes mant\u00eam seu valor fixo.", "Constantes s\u00e3o usadas apenas para apresentar resultados, enquanto vari\u00e1veis s\u00e3o para c\u00e1lculos.", "Vari\u00e1veis s\u00e3o armazenadas na mem\u00f3ria principal, enquanto constantes ficam no disco.", "N\u00e3o h\u00e1 diferen\u00e7a relevante entre elas."]', 0, 'A principal característica de uma variável é que seu valor pode ser modificado ao longo da execução de um programa, em contraste com as constantes, que possuem um valor imutável definido.', '2026-03-11T17:55:59.233342+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('72829429-1c69-4118-9764-4935f579f326', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'Qual tipo de dado é mais adequado para armazenar um número inteiro como 10 ou -5?', '["Booleano", "Ponto flutuante (decimal)", "Inteiro", "Caractere"]', 2, 'O tipo de dado ''inteiro'' (integer) é projetado para armazenar valores numéricos sem fração decimal.', '2026-03-11T17:55:59.233342+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('711ad570-8e31-4534-875e-ab7efed680b7', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'Em programação, o que um tipo de dado ''booleano'' representa?', '["Uma sequ\u00eancia de caracteres textuais.", "Um n\u00famero com casas decimais.", "Um valor l\u00f3gico que pode ser verdadeiro ou falso.", "Um n\u00famero inteiro espec\u00edfico."]', 2, 'O tipo booleano possui apenas dois valores possíveis: verdadeiro (true) ou falso (false), sendo fundamental para operações lógicas e condicionais.', '2026-03-11T17:55:59.233342+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('40db9572-2c58-4e39-83fe-307a97060557', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'Qual instrução é utilizada para executar um bloco de código apenas se uma condição específica for verdadeira?', '["else", "for", "while", "if"]', 3, 'A instrução ''if'' é o comando fundamental para a criação de blocos de código condicionais. Ela verifica uma condição e, se for verdadeira, executa as instruções dentro de seu bloco.', '2026-03-11T17:56:35.010011+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6f397a41-f94b-4c6a-86e8-bc598eee1956', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'Quando utilizamos a estrutura condicional ''else if'' em um programa?', '["Quando queremos ignorar uma condi\u00e7\u00e3o anterior.", "Para verificar uma nova condi\u00e7\u00e3o apenas se a condi\u00e7\u00e3o ''if'' anterior for falsa.", "Para indicar o fim de um bloco de c\u00f3digo.", "Para definir o nome de uma vari\u00e1vel."]', 1, '''Else if'' (ou ''elif'' em algumas linguagens) é usado para testar uma condição adicional quando a condição anterior (do ''if'' ou de outros ''else if'') não foi atendida.', '2026-03-11T17:56:35.010011+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f190fc32-1702-4d2e-ba96-c5a235462867', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'Para que serve a instrução ''else'' em uma estrutura condicional?', '["Para definir uma nova condi\u00e7\u00e3o a ser testada.", "Para executar um bloco de c\u00f3digo se NENHUMA das condi\u00e7\u00f5es anteriores (if/else if) for verdadeira.", "Para iniciar um la\u00e7o de repeti\u00e7\u00e3o.", "Para declarar uma vari\u00e1vel global."]', 1, 'O bloco ''else'' é executado como um ''plano B'', ou seja, caso a condição do ''if'' e todas as condições dos ''else if'' associados sejam avaliadas como falsas.', '2026-03-11T17:56:35.010011+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('e14802dc-79cb-4f7f-ae20-1ef741d8d4bb', '7b8be525-9faa-4327-acba-376d5dd240e2', 'Qual laço de repetição é mais adequado quando o número de iterações é conhecido previamente?', '["while", "if", "for", "switch"]', 2, 'O laço ''for'' é ideal quando se sabe exatamente quantas vezes uma tarefa precisa ser repetida, pois ele gerencia a inicialização, condição e incremento/decremento em uma única linha.', '2026-03-11T17:56:39.615408+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('946565dd-0696-4fba-b680-3155b3ba1aeb', '7b8be525-9faa-4327-acba-376d5dd240e2', 'Em um laço ''while'', quando o bloco de código será executado?', '["Apenas uma vez, independentemente da condi\u00e7\u00e3o.", "Enquanto a condi\u00e7\u00e3o especificada for VERDADEIRA.", "Apenas se a condi\u00e7\u00e3o for FALSA.", "At\u00e9 que haja um erro de sintaxe."]', 1, 'O laço ''while'' continua executando o bloco de código enquanto a condição especificada permanecer verdadeira. Assim que a condição se torna falsa, o laço é encerrado.', '2026-03-11T17:56:39.615408+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('fb4cd738-a109-4982-816d-dea98f2c920a', '7b8be525-9faa-4327-acba-376d5dd240e2', 'Qual a diferença entre ''break'' e ''continue'' dentro de um laço?', '["''break'' encerra o la\u00e7o atual, enquanto ''continue'' pula para a pr\u00f3xima itera\u00e7\u00e3o.", "''break'' pula para a pr\u00f3xima itera\u00e7\u00e3o, enquanto ''continue'' encerra o la\u00e7o.", "Ambos fazem a mesma coisa: encerrar o la\u00e7o.", "Ambos pulam para a pr\u00f3xima itera\u00e7\u00e3o do la\u00e7o."]', 0, '''Break'' é usado para sair imediatamente de um laço, interrompendo sua execução. ''Continue'' pula o restante das instruções da iteração atual e inicia a próxima iteração do laço.', '2026-03-11T17:56:39.615408+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('697b9a06-ff9e-40b3-b2fd-470d2be861cf', 'd50da46e-a40b-4d38-bdf7-914b2d78aad7', 'Qual palavra-chave é usada para definir uma função em Python?', '["A) function", "B) define", "C) def", "D) func"]', 0, NULL, '2026-03-12T22:45:28.4556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('d78ebfa4-411a-4b1b-949b-aeba11b0e7e6', 'd50da46e-a40b-4d38-bdf7-914b2d78aad7', 'Qual é o principal benefício de usar funções em um programa?', '["A) Aumentar o tamanho do c\u00f3digo.", "B) Reduzir a legibilidade do c\u00f3digo.", "C) Reutilizar c\u00f3digo e organizar o programa.", "D) Tornar o programa mais lento."]', 0, NULL, '2026-03-12T22:45:28.4556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('9aee71fd-28c5-4154-ab6b-17c1e81d2009', 'd50da46e-a40b-4d38-bdf7-914b2d78aad7', 'Se uma variável é definida dentro de uma função, qual é o seu escopo padrão?', '["A) Global", "B) Local", "C) M\u00f3dulo", "D) Classe"]', 0, NULL, '2026-03-12T22:45:28.4556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('bf68be6f-08ef-4ec3-87bc-3c6949601c2e', 'f4125bb3-7b79-44b6-a7d1-7673e8c041ba', 'Qual estrutura de dados permite armazenar uma coleção ordenada e mutável de itens?', '["A) Tupla", "B) Dicion\u00e1rio", "C) Lista", "D) Conjunto"]', 0, NULL, '2026-03-12T22:45:31.631882+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('133b9fc7-b452-4187-a0ed-5ae32f68af43', 'f4125bb3-7b79-44b6-a7d1-7673e8c041ba', 'Qual das seguintes estruturas de dados armazena pares chave-valor?', '["A) Lista", "B) Tupla", "C) Dicion\u00e1rio", "D) Conjunto"]', 0, NULL, '2026-03-12T22:45:31.631882+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('33b8b981-67ee-4051-aef9-1d2f5601405a', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'Qual o resultado da expressão lógica ''verdadeiro E falso''?', '["Verdadeiro", "Falso", "Erro", "Indefinido"]', 1, 'O operador lógico ''E'' (AND) retorna verdadeiro apenas se ambos os operandos forem verdadeiros. Neste caso, como um é falso, o resultado é falso.', '2026-03-11T17:56:38.747966+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b95296eb-04bf-4c9a-b325-72addc19f904', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'Em expressões, qual operador tem precedência sobre o operador de adição (+)?', '["Subtra\u00e7\u00e3o (-)", "Multiplica\u00e7\u00e3o (*)", "Compara\u00e7\u00e3o (==)", "Atribui\u00e7\u00e3o ( = )"]', 1, 'Em geral, a multiplicação e a divisão têm maior precedência do que a adição e a subtração, significando que são avaliadas primeiro em uma expressão.', '2026-03-11T17:56:38.747966+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('5881eb84-73a4-4d28-a799-ff673ae607e2', '1e220f09-6464-4328-8b04-2b8c5749e869', 'Qual a principal vantagem de usar funções em programação?', '["Aumentar o n\u00famero de linhas de c\u00f3digo.", "Permitir a reutiliza\u00e7\u00e3o de c\u00f3digo e tornar o programa mais organizado e leg\u00edvel.", "Tornar o programa mais lento.", "Ignorar erros de sintaxe."]', 1, 'Funções encapsulam blocos de código que realizam tarefas específicas, permitindo que sejam chamadas múltiplas vezes de diferentes partes do programa, promovendo modularidade e evitando duplicação de código.', '2026-03-11T17:57:22.202638+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f385b565-70c3-4065-82e5-1a075c9436d8', '1e220f09-6464-4328-8b04-2b8c5749e869', 'O que são ''parâmetros'' em uma função?', '["Os valores que a fun\u00e7\u00e3o retorna.", "Vari\u00e1veis locais dentro da fun\u00e7\u00e3o.", "Valores que s\u00e3o passados para a fun\u00e7\u00e3o quando ela \u00e9 chamada, permitindo que ela opere sobre dados espec\u00edficos.", "O nome da fun\u00e7\u00e3o."]', 2, 'Parâmetros são como variáveis de entrada para uma função. Eles recebem valores específicos quando a função é invocada, informando dados para que a função possa trabalhar.', '2026-03-11T17:57:22.202638+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2df65a73-4ba9-4836-a9fe-f473f939a0e1', '1e220f09-6464-4328-8b04-2b8c5749e869', 'Qual a finalidade da instrução ''return'' dentro de uma função?', '["Iniciar um novo la\u00e7o de repeti\u00e7\u00e3o.", "Fazer a fun\u00e7\u00e3o parar de executar e retornar um valor (ou nenhum valor) para o local onde foi chamada.", "Definir uma vari\u00e1vel global.", "Imprimir uma mensagem de erro."]', 1, 'A instrução ''return'' é usada para encerrar a execução de uma função e, opcionalmente, enviar um valor de volta para o código que a chamou. Sem ''return'', a função pode retornar um valor padrão (como ''undefined'' ou ''null'').', '2026-03-11T17:57:22.202638+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('64ebb0e2-4908-4611-920c-347eb471027b', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'Qual estrutura de dados é mais adequada para armazenar uma coleção ordenada de itens, onde cada item pode ser acessado por um índice numérico?', '["Dicion\u00e1rio (ou Mapa)", "Array (ou Lista)", "Vari\u00e1vel booleana", "Constante num\u00e9rica"]', 1, 'Arrays ou listas armazenam elementos em uma sequência ordenada, permitindo o acesso a cada elemento através de seu índice, que geralmente começa em zero.', '2026-03-11T17:57:25.870778+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('5cc2375d-e0a9-4ebc-9c27-179b03d0a25e', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'O que é considerado uma ''boa prática'' em programação?', '["Escrever c\u00f3digo complexo e dif\u00edcil de ler para impressionar colegas.", "Utilizar nomes de vari\u00e1veis gen\u00e9ricos e pouco descritivos.", "Escrever c\u00f3digo claro, organizado, eficiente e f\u00e1cil de manter.", "Ignorar erros e n\u00e3o documentar o c\u00f3digo."]', 2, 'Boas práticas envolvem escrever código que seja não apenas funcional, mas também esteticamente agradável, fácil de entender para outros desenvolvedores (e para você mesmo no futuro) e que minimize a possibilidade de erros.', '2026-03-11T17:57:25.870778+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0358e208-7e7b-481a-8e1f-bdeb77fc3bb5', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'Em uma estrutura de dados como um dicionário (ou objeto), como acessamos um valor específico?', '["Atrav\u00e9s de seu \u00edndice num\u00e9rico.", "Atrav\u00e9s de uma chave associada a esse valor.", "Percorrendo todos os valores sequencialmente.", "N\u00e3o \u00e9 poss\u00edvel acessar valores espec\u00edficos."]', 1, 'Dicionários associam valores a chaves (geralmente strings). O acesso aos valores se dá pela utilização da chave correspondente, de forma direta e não sequencial.', '2026-03-11T17:57:25.870778+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('aa0f1471-5d42-4144-83e1-e63d1fe9ce66', 'f4125bb3-7b79-44b6-a7d1-7673e8c041ba', 'Qual das seguintes afirmações sobre tuplas é verdadeira?', '["A) Tuplas s\u00e3o mut\u00e1veis.", "B) Tuplas s\u00e3o criadas usando chaves `{}`.", "C) Tuplas s\u00e3o imut\u00e1veis.", "D) Tuplas n\u00e3o podem conter elementos de diferentes tipos."]', 0, NULL, '2026-03-12T22:45:31.631882+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a9828242-4c61-4ec6-a54f-8608091b7d7d', '31a78d46-505f-4380-9e15-e77b4e9fce4e', 'Em POO, o que é um ''objeto''?', '["A) Uma planta para criar outros objetos.", "B) Uma inst\u00e2ncia de uma classe.", "C) Um tipo de dado primitivo.", "D) Uma fun\u00e7\u00e3o que retorna um valor."]', 0, NULL, '2026-03-12T22:46:43.331895+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('cd7e5bba-c0ee-47ef-9f0f-43386e294973', '31a78d46-505f-4380-9e15-e77b4e9fce4e', 'Qual método é automaticamente chamado quando um novo objeto é criado a partir de uma classe em Python?', '["A) `__start__()`", "B) `__call__()`", "C) `__init__()`", "D) `__create__()`"]', 0, NULL, '2026-03-12T22:46:43.331895+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('8ddeda17-b2c8-4757-a27f-eb7b32da5435', '31a78d46-505f-4380-9e15-e77b4e9fce4e', 'Qual conceito de POO permite que uma classe herde atributos e métodos de outra classe?', '["A) Encapsulamento", "B) Polimorfismo", "C) Abstra\u00e7\u00e3o", "D) Heran\u00e7a"]', 0, NULL, '2026-03-12T22:46:43.331895+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2a40d618-3e20-4094-8e1d-558c5a59584c', 'be05ea69-bd00-4f76-a13f-8fd88690690f', 'Qual modo de abertura de arquivo é usado para ler um arquivo existente?', '["A) ''w''", "B) ''a''", "C) ''r''", "D) ''x''"]', 0, NULL, '2026-03-12T22:46:47.65555+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('74670720-6b15-4095-8150-e11c85304a38', 'be05ea69-bd00-4f76-a13f-8fd88690690f', 'Qual dos seguintes métodos do módulo `json` é usado para converter um objeto Python em uma string JSON?', '["A) `json.load()`", "B) `json.dump()`", "C) `json.loads()`", "D) `json.dumps()`"]', 0, NULL, '2026-03-12T22:46:47.65555+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('44bd9951-bbf7-4fee-8171-18cc26fa0128', 'be05ea69-bd00-4f76-a13f-8fd88690690f', 'Qual é o principal benefício de usar `with open(...)` para manipular arquivos?', '["A) Permite escrever em um arquivo sem abr\u00ed-lo explicitamente.", "B) Garante que o arquivo seja automaticamente fechado, mesmo que ocorra um erro.", "C) Abre o arquivo no modo de escrita por padr\u00e3o.", "D) Converte automaticamente o conte\u00fado do arquivo para JSON."]', 0, NULL, '2026-03-12T22:46:47.65555+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2991e810-1752-40e9-8ce8-c2fa77bf3892', 'fc6e58d0-5392-42ed-95c1-0a3e381af6ec', 'Qual bloco de código é executado independentemente de uma exceção ter ocorrido ou não?', '["A) `try`", "B) `except`", "C) `else`", "D) `finally`"]', 0, NULL, '2026-03-12T22:46:56.10682+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('520948fe-446e-4937-b6bd-f165b08c344f', 'fc6e58d0-5392-42ed-95c1-0a3e381af6ec', 'Qual nível de log é geralmente usado para registrar informações detalhadas, úteis para a depuração?', '["A) `INFO`", "B) `WARNING`", "C) `DEBUG`", "D) `ERROR`"]', 0, NULL, '2026-03-12T22:46:56.10682+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('7cc047a7-e7db-4c8d-a908-21e852dce928', 'fc6e58d0-5392-42ed-95c1-0a3e381af6ec', 'Qual palavra-chave é usada para levantar (raise) uma exceção manualmente em Python?', '["A) `throw`", "B) `except`", "C) `raise`", "D) `handle`"]', 0, NULL, '2026-03-12T22:46:56.10682+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('81669b02-a53e-49f6-98b5-1de22c5e6e2c', '624067c0-79d7-4897-8d40-b27a2b6e76b9', 'Qual é o principal objetivo dos testes automatizados?', '["A) Aumentar o n\u00famero de bugs no c\u00f3digo.", "B) Garantir que o c\u00f3digo funcione conforme o esperado e identificar regress\u00f5es.", "C) Tornar o processo de desenvolvimento mais lento.", "D) Substituir a depura\u00e7\u00e3o manual completamente."]', 0, NULL, '2026-03-12T22:48:04.272326+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4b036b46-ecf5-4474-90ac-1c8df8a9fdbc', '624067c0-79d7-4897-8d40-b27a2b6e76b9', 'No `unittest`, qual método é usado para verificar se dois valores são iguais?', '["A) `self.assertTrue()`", "B) `self.assertEqual()`", "C) `self.assertRaises()`", "D) `self.assertFalse()`"]', 0, NULL, '2026-03-12T22:48:04.272326+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f4a00da5-717b-4c9b-98e3-8511861fa0bd', '624067c0-79d7-4897-8d40-b27a2b6e76b9', 'O que é Test-Driven Development (TDD)?', '["A) Escrever o c\u00f3digo primeiro e depois os testes.", "B) Escrever testes apenas quando um bug \u00e9 encontrado.", "C) Escrever os testes antes de escrever o c\u00f3digo de produ\u00e7\u00e3o.", "D) N\u00e3o escrever testes em absoluto."]', 0, NULL, '2026-03-12T22:48:04.272326+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0331a755-964a-44ad-9e7c-711b7872bd3d', 'd78a7bad-478f-430e-b436-e89b6e881c3a', 'Qual é a principal função de um ambiente virtual em Python?', '["A) Criar um backup de todo o sistema.", "B) Isolacionar as depend\u00eancias de um projeto Python de outros projetos.", "C) Acelerar a execu\u00e7\u00e3o de scripts Python.", "D) Permitir a instala\u00e7\u00e3o de pacotes diretamente no sistema operacional."]', 0, NULL, '2026-03-12T22:48:04.812648+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4b9834d7-d38d-40db-91e9-6cf878217a03', 'd78a7bad-478f-430e-b436-e89b6e881c3a', 'Qual biblioteca padrão do Python é comumente usada para ler argumentos da linha de comando?', '["A) `os`", "B) `sys`", "C) `argparse`", "D) `json`"]', 0, NULL, '2026-03-12T22:48:04.812648+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('08819154-a731-4a2d-ae9c-fa1fad2f2540', 'd78a7bad-478f-430e-b436-e89b6e881c3a', 'A criação de um executável (`.exe`) a partir de um script Python geralmente é feita para:', '["A) Tornar o c\u00f3digo mais seguro.", "B) Distribuir o aplicativo para usu\u00e1rios que podem n\u00e3o ter Python instalado.", "C) Aumentar a performance do programa.", "D) Facilitar a depura\u00e7\u00e3o."]', 0, NULL, '2026-03-12T22:48:04.812648+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('55dbd36e-2bad-447e-b1b9-cfd2a7f47822', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'In the BANT framework, the ''A'' refers to:', '["Authority (Autoridade)", "Accountability (Responsabilidade)", "Agreement", "Analysis (An\u00e1lise)"]', 0, '''Authority'' refers to the contact''s ability to make purchasing decisions and their level of power to influence the decision-making process within their organization.', '2026-03-12T04:41:11.3923+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f0608c30-d84f-44d4-b9a9-a41081bcc8ed', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'Which of the following psychological factors has the greatest impact on B2B purchasing decisions, according to the principle of reciprocity?', '["The desire for social conformity.", "The perception that the other party did a favor or offered a benefit.", "Loss aversion.", "The need for consistency."]', 1, 'The principle of reciprocity suggests that people feel compelled to return favors or benefits received. In B2B sales, offering value in advance or sharing relevant information can create a sense of obligation in the buyer.', '2026-03-12T04:41:13.227894+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1e4909f6-7bf5-4821-b020-4dc52120a87f', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'Which letter in the MEDDIC framework represents the process by which the buyer validates the proposed solution internally and externally?', '["M (Metric)", "E (Economic Buyer)", "D (Decision Criteria)", "C (Champion)"]', 2, '''Decision Criteria'' is what the buyer uses to evaluate the different options. Identifying and aligning with these criteria is crucial. In a broader sense, internal validation is part of this process.', '2026-03-12T04:41:20.695391+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('7437edf2-2262-47a3-a6f9-c7bb306d4439', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'Active listening in B2B negotiations primarily involves:', '["Defending your point of view vehemently.", "Interrupting frequently to ask clarifying questions.", "Agree with all of the buyer''s statements to avoid conflict.", "Pay full attention, understand, respond to, and retain the speaker''s information."]', 3, 'Active listening goes beyond hearing; it involves demonstrating understanding through verbal and non-verbal signs, confirming what was said and retaining information for a more effective response.', '2026-03-12T04:41:22.184944+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2cbde22d-23af-48bd-a032-64cb17c61f00', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'The technique of questioning in SPIN Selling (Situation, Problem, Implication, Need-Payoff) is focused on:', '["Present the solution quickly to create immediate impact.", "Deeply understanding the client''s needs through a logical flow of questions.", "Obtain a quick commitment from the buyer.", "Focus only on the technical aspects of the product."]', 1, 'SPIN Selling is a consultative sales methodology that uses strategic questions to uncover the client''s problems (**P**roblem), explore their consequences (**I**mplication), and then connect the solution to the satisfaction of a clear need (**N**eed-Payoff).', '2026-03-12T04:41:29.222906+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('05df1e05-e1c6-4593-83d8-69f3eb6e70f6', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'What is the first crucial step to building trust in a B2B relationship?', '["Point out the competitor''s mistakes.", "Demonstrate deep knowledge of the client''s business.", "Offer aggressive discounts from the start.", "Talk only about your product or service."]', 1, 'Demonstrating that you understand the client''s challenges, objectives, and market is fundamental to building credibility and trust, showing that you are there to help solve real problems.', '2026-03-12T04:41:31.446563+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6dd4d5ff-2f7e-4d29-9abe-66511ba916a1', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'What is the best initial approach when dealing with a price objection in B2B sales?', '["Offer a discount immediately to close the deal.", "Ignore the objection and continue the presentation.", "Apologize for the price and wait for the customer''s reaction.", "Validate the customer''s concern and seek to understand the perceived value."]', 3, 'It is fundamental to validate the customer''s concern, demonstrating that you have listened and understood. Subsequently, it is necessary to recontextualize the price in relation to the delivered value and the benefits the customer will obtain.', '2026-03-12T04:42:05.740752+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('d0a0500d-023f-4df5-b572-04bdb4b86049', '86104405-5e60-496d-954b-cdac7965204c', 'The principle of ''social proof'' in ethical persuasion is based on the idea that:', '["People tend to follow the actions and opinions of others, especially in situations of uncertainty.", "The opinion of an authority figure is always the most reliable.", "The scarcity of an item increases its perceived value.", "People are more likely to agree with those they like."]', 0, 'Social proof suggests that when we are unsure about how to act, we look at the behavior of other people to guide us. In sales, this translates into testimonials, case studies, and success stories.', '2026-03-12T04:42:07.963922+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c822e9f1-806b-4fa3-bc99-fc6c8b370675', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'An objection of the type ''We don''t have time for this right now'' usually indicates:', '["A real need for more time.", "A problem of priority or a lack of clarity regarding the benefit.", "That the customer has already decided not to buy.", "An attempt to delay a financial commitment."]', 1, 'This objection frequently signals that the buyer has not perceived the value or urgency of your proposal in relation to their current priorities. It is necessary to realign the value and the positive impacts.', '2026-03-12T04:42:13.682897+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a70f9f5a-5f72-4f3f-b823-68567bd7b280', '86104405-5e60-496d-954b-cdac7965204c', 'Which of the following examples best illustrates the principle of ''scarcity'' in ethical persuasion?', '["A salesperson who demonstrates deep technical knowledge.", "A buyer who shares confidential information.", "A discount offer valid only for a limited time or for the first customers.", "The use of positive reviews from previous customers."]', 2, 'The principle of scarcity suggests that the limited availability of a product or offer increases its attractiveness. Limiting time or quantity can create a sense of urgency and encourage action.', '2026-03-12T04:42:17.102542+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('565401ee-fec0-40dd-8a2c-a1a79f16cb93', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'Which objection handling technique involves reframing the customer''s objection into a positive statement before responding?', '["Active Listening", "Reaffirmation/Reframing Technique", "Clarifying Questions", "Bypassing the Objection"]', 1, 'The technique of restatement (or reframing) seeks to transform the customer''s objection into something that can be answered more constructively, demonstrating understanding before presenting the solution.', '2026-03-12T04:42:21.707755+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0dc64fd1-bb3f-433c-afaf-2cbc91e45f99', '86104405-5e60-496d-954b-cdac7965204c', 'To apply the principle of ''liking'' ethically in B2B persuasion, a salesperson must:', '["Pretend interest in the client''s hobbies.", "Focus only on finding common ground and genuine interests.", "Offering expensive gifts to create a bond.", "Unnecessarily sharing personal information to create rapport."]', 1, 'The principle of liking is ethically applied when the salesperson seeks to find sincere affinities with the customer, such as common professional interests, shared values, or a compatible communication style, establishing a genuine connection.', '2026-03-12T04:42:25.56782+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('d8216b9a-0923-4fe5-8aea-4721653aefcd', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'In the preparation phase for a B2B negotiation, what is the most important first step?', '["Define your minimum acceptance price.", "Deeply analyze the interests and needs of the other party.", "Prepare your slide presentation.", "Think of the most likely objections."]', 1, 'Understanding the interests and objectives of the other party is fundamental to creating a proposal that meets their needs and facilitates the negotiation. Without this, the preparation remains incomplete.', '2026-03-12T04:42:59.636522+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b91e7c83-158f-44d3-8ba6-0f00db7e5013', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'What does ''Bargaining'' mean in a B2B negotiation?', '["The stage in which you present your final offer with no room for discussion.", "The process of exchanging concessions to reach an agreement, where both parties yield on certain points to achieve a common objective.", "The phase in which you declare victory and wait for the contract to be signed.", "The attempt to win at all costs by exploiting the other person''s weaknesses."]', 1, 'Bargaining is a process of give and take, where concessions are made to find common ground and reach an agreement acceptable to both parties involved.', '2026-03-12T04:43:07.77773+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('88ec6beb-d8d3-4612-9ea8-587101af375a', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'What is the best strategy to close a B2B deal after a successful negotiation?', '["Keep adding more offers and benefits to ''guarantee'' the sale.", "Act very cooperatively and let the customer define all the terms.", "Make a clear summary of the agreed terms and seek the client''s final commitment.", "Postpone the closing to see if the client changes their mind."]', 2, 'After the negotiation, a clear summary of the agreed points and the pursuit of a final commitment help to solidify the agreement and avoid future misunderstandings, ensuring a professional closing.', '2026-03-12T04:43:16.494373+00:00') ON CONFLICT DO NOTHING;

-- Data for course_flashcards
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('554fc4b6-f13e-4bab-924b-33bb2639efa0', 'c4911477-5546-4ace-9680-00d374416369', 'Qual tipo de dado pode ser analisado por IA para um profissional de recursos humanos identificar talentos?', 'Dados como histórico de desempenho, participação em treinamentos, feedback de colegas e indicadores de engajamento podem ser analisados para identificar padrões associados a alto potencial.', '2026-03-03T20:27:07.798393+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b276dc8a-9e8e-4ef1-8b4c-0e68585677a3', 'c4911477-5546-4ace-9680-00d374416369', 'Como a IA pode ajudar um profissional de logística a otimizar rotas de entrega?', 'A IA pode analisar dados de tráfego em tempo real, condições climáticas, cronogramas de entrega e capacidade dos veículos para calcular as rotas mais eficientes.', '2026-03-03T20:27:07.798393+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('3ae46c88-a3f5-4ec8-8ddf-29edbe6054ee', 'c4911477-5546-4ace-9680-00d374416369', 'O que significa ''análise preditiva'' no contexto do uso de IA para negócios?', 'Análise preditiva utiliza dados históricos e algoritmos de IA para prever resultados futuros, como a probabilidade de um cliente cancelar um serviço ou o volume de vendas esperado para o próximo trimestre.', '2026-03-03T20:27:07.798393+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('968defbd-9a96-41bb-a5c2-08819e447635', 'c4911477-5546-4ace-9680-00d374416369', 'Quais ferramentas podem ser úteis para um profissional não técnico criar visualizações de dados a partir de análises de IA?', 'Ferramentas como Tableau, Power BI, Google Data Studio e até mesmo recursos integrados em planilhas avançadas podem ser utilizados para criar visualizações interativas.', '2026-03-03T20:27:07.798393+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('bada42d7-72f2-4b28-af62-16c844aa4bc3', 'c4911477-5546-4ace-9680-00d374416369', 'Como a IA pode auxiliar na detecção de fraudes para um profissional financeiro?', 'A IA pode analisar transações em tempo real, identificar padrões anômalos e sinais de comportamento suspeito que indicariam uma possível fraude, alertando o analista.', '2026-03-03T20:27:07.798393+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('05f90674-6048-4122-babc-52f2cdc4649c', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'Quais são exemplos de assistentes virtuais baseados em IA que podem auxiliar em tarefas administrativas?', 'Exemplos incluem assistentes como Siri, Google Assistant e Alexa, que podem agendar reuniões, definir lembretes e realizar pesquisas rápidas.', '2026-03-03T20:27:14.306949+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d9a685bc-7f39-4762-9db2-b0b9982c9a49', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'Como ferramentas de IA podem otimizar a criação de conteúdo escrito para um profissional de marketing?', 'Ferramentas como modelos de linguagem (ex: ChatGPT) podem auxiliar na geração de rascunhos, sugestão de títulos, refino de textos e revisão gramatical e estilística.', '2026-03-03T20:27:14.306949+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('40473a37-5983-465a-ae8c-971ac0270414', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'Para um gerente de projetos, como uma ferramenta de IA pode ser útil para analisar o progresso de um projeto?', 'Ferramentas de IA podem analisar dados de tarefas, identificar gargalos em potencial, prever atrasos e sugerir alocações de recursos mais eficientes.', '2026-03-03T20:27:14.306949+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f06054cf-960d-44c9-b945-83b9f82a07d7', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'O que caracteriza uma ferramenta de IA como ''sem código'' (no-code)?', 'Uma ferramenta ''sem código'' permite que usuários criem aplicações ou automatizem tarefas utilizando interfaces visuais, como arrastar e soltar elementos, sem a necessidade de escrever ou entender código de programação.', '2026-03-03T20:27:14.306949+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('9fa4d5e3-56f4-496d-b1fb-822737d1a187', 'dd533a4c-6322-4e32-ac58-bc117878863b', 'Quais tipos de dados uma ferramenta de IA pode ajudar a analisar para um profissional de vendas?', 'Ela pode analisar dados sobre o comportamento do cliente, histórico de compras, interações com a equipe de vendas e informações de mercado para identificar oportunidades de vendas e prever o envolvimento do cliente.', '2026-03-03T20:27:14.306949+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e1ba1d5e-88b3-4c95-b0f1-d6d0eeb37d09', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'O que significa o termo ''Inteligência Artificial'' (IA) em termos práticos para um profissional não técnico?', 'IA refere-se à capacidade de sistemas computacionais executarem tarefas que, em geral, requerem inteligência humana, como aprender, resolver problemas e tomar decisões.', '2026-03-03T20:27:14.95059+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('3db6ee19-f224-488d-bdd8-14668a00f25b', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'Quais são os dois tipos principais de IA que um profissional não técnico deve conhecer inicialmente?', 'Os dois tipos principais são IA Fraca (ou Estreita), focada em uma tarefa específica, e IA Forte (ou Geral), com capacidades humanas gerais (ainda em desenvolvimento).', '2026-03-03T20:27:14.95059+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ca4f7ffb-31be-4777-a630-b8894028db82', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'Como a IA pode auxiliar na tomada de decisões para um gestor de marketing?', 'A IA pode analisar grandes volumes de dados de clientes, identificar padrões de comportamento e prever tendências de mercado, auxiliando na criação de campanhas mais eficazes.', '2026-03-03T20:27:14.95059+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0a4ec91e-48f4-4399-ad96-304071ba13cd', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Que tipo de ferramenta de IA é comumente usada para auxiliar na escrita de textos?', 'Modelos de linguagem avançados (como Generative Pre-trained Transformers - GPT).', '2026-03-05T20:18:14.838195+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7cd68217-d63b-4904-a786-4351ef2661cd', '1ab5cbcf-b36f-4143-a86f-f6daf38797cf', 'Neurônio Artificial', 'Unidade computacional básica de uma rede neural, que recebe entradas, aplica pesos e uma função de ativação.', '2026-03-01T23:23:30.486964+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b7fe66be-5c44-4e82-ae57-8ca8e6c453ac', '1ab5cbcf-b36f-4143-a86f-f6daf38797cf', 'Inspiração Biológica', 'O cérebro humano e o funcionamento de seus neurônios serviram de modelo para a concepção das Redes Neurais Artificiais.', '2026-03-01T23:23:30.486964+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a5876552-82fd-451d-9808-e459489db76e', '1ab5cbcf-b36f-4143-a86f-f6daf38797cf', 'Camada de Entrada', 'A primeira camada de uma rede neural, responsável por receber os dados brutos do problema.', '2026-03-01T23:23:30.486964+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d3487572-d4e8-4639-9d3e-163ec3953c54', '1ab5cbcf-b36f-4143-a86f-f6daf38797cf', 'Camada Oculta', 'Camadas intermediárias em uma rede neural que realizam a maior parte do processamento e extração de características dos dados.', '2026-03-01T23:23:30.486964+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d2e80ec3-6394-4ede-8481-f83f8ea5bdbd', '1ab5cbcf-b36f-4143-a86f-f6daf38797cf', 'Camada de Saída', 'A última camada de uma rede neural, que produz o resultado final da predição ou classificação.', '2026-03-01T23:23:30.486964+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('6eea076a-f25e-409f-9021-27af7b72485e', '07d8198d-f341-4110-8a8c-a568f6b42110', 'Pesos (Weights)', 'Valores numéricos associados às conexões entre neurônios, que determinam a influência de uma entrada na saída.', '2026-03-01T23:24:05.07384+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('81b3e6a9-6eb3-49c0-bdd9-fdc6790ad85d', '07d8198d-f341-4110-8a8c-a568f6b42110', 'Viés (Bias)', 'Um termo adicional em um neurônio que permite ajustar o limiar de ativação, independentemente das entradas.', '2026-03-01T23:24:05.07384+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d8e65c9e-770c-46d4-a42b-53b32e947e92', '07d8198d-f341-4110-8a8c-a568f6b42110', 'Função de Custo (Loss Function)', 'Mede a diferença entre a saída prevista pela rede e o valor real desejado.', '2026-03-01T23:24:05.07384+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('377dea26-8142-4d03-9abe-32d4f1dd5f89', '07d8198d-f341-4110-8a8c-a568f6b42110', 'Retropropagação (Backpropagation)', 'Algoritmo para calcular gradientes e ajustar pesos da rede neural durante o treinamento.', '2026-03-01T23:24:05.07384+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('5a4e9ced-ea7c-4089-91e9-942db3d7f511', '07d8198d-f341-4110-8a8c-a568f6b42110', 'Otimizadores (ex: Gradiente Descendente)', 'Algoritmos que utilizam os gradientes calculados pelo backpropagation para atualizar os pesos da rede de forma eficiente.', '2026-03-01T23:24:05.07384+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('6f552d69-1087-461c-a7e1-6da9124a4eff', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Rede Neural Convolucional (CNN)', 'Tipo de rede neural especializada em processar dados com uma topologia de grade, como imagens, utilizando camadas convolucionais e de pooling.', '2026-03-01T23:24:31.941556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c6873d83-d1ea-4e55-86f6-c54501634129', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Rede Neural Recorrente (RNN)', 'Tipo de rede neural projetada para lidar com dados sequenciais, onde a saída em um passo de tempo depende de entradas anteriores.', '2026-03-01T23:24:31.941556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4be160f8-37ac-4944-860b-b0ab6752a8a2', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Perceptron Multicamadas (MLP)', 'Uma rede neural feedforward básica com uma ou mais camadas ocultas, utilizada para tarefas de classificação e regressão em dados não estruturados.', '2026-03-01T23:24:31.941556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('5d0d53ed-fdda-43f2-b38e-f5598694dca3', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Aplicações de CNNs', 'Reconhecimento de imagens, detecção de objetos, segmentação de imagens, visão computacional.', '2026-03-01T23:24:31.941556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4cd0edc4-6a7c-480e-b323-a3f3b8566a1a', '14ab3efb-b6af-4510-b9fd-2892129aaf0b', 'Aplicações de RNNs', 'Processamento de Linguagem Natural (PLN), tradução automática, reconhecimento de fala, análise de séries temporais.', '2026-03-01T23:24:31.941556+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('2b32e171-9b0c-4868-8dfe-c75d3ac6c601', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'Por que é importante para profissionais de diversas áreas entenderem sobre IA, mesmo sem serem da área de tecnologia?', 'O entendimento da IA permite identificar oportunidades de otimização, inovação e aprimoramento de processos em suas respectivas áreas de atuação, tornando-os mais competitivos.', '2026-03-03T20:27:14.95059+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f8fae5a6-4e58-4a60-8984-409410950aa9', 'a0d4778a-afa7-4740-a25a-923230b2e040', 'Qual a principal diferença entre aprendizado de máquina (machine learning) e aprendizado profundo (deep learning) na perspectiva de um usuário final?', 'O aprendizado de máquina envolve algoritmos que aprendem com dados sem serem explicitamente programados. O aprendizado profundo é um subconjunto do machine learning que utiliza redes neurais com muitas camadas para aprender padrões.', '2026-03-03T20:27:14.95059+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('3bc621a2-d73c-4033-872a-4316b9f229d7', '040f437a-eaf3-433c-be93-36008614769b', 'Como a IA pode criar novas oportunidades de trabalho para profissionais não técnicos?', 'Ao surgir novas funções como ''curador de prompts'', ''analista de dados com IA'' (foco em interpretação), ''especialista em implementação de ferramentas de IA'' e ''consultor de ética em IA''.', '2026-03-03T20:27:43.128235+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('cf22e8f0-0ebe-4795-93b2-59f0e59b21cf', '040f437a-eaf3-433c-be93-36008614769b', 'O que significa ''colaboração humano-IA''?', 'É um modelo onde humanos e sistemas de IA trabalham juntos, cada um aproveitando suas próprias forças para atingir um objetivo comum, resultando em maior eficiência e qualidade.', '2026-03-03T20:27:43.128235+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e2cda21c-1950-44ca-98bb-e523b234a62b', '040f437a-eaf3-433c-be93-36008614769b', 'Quais são os riscos associados à automação por IA que os profissionais devem estar cientes?', 'Riscos como perda de empregos em setores mais suscetíveis à automação, aprofundamento de desigualdades e a necessidade de requalificação constante da força de trabalho.', '2026-03-03T20:27:43.128235+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('88eb381c-3695-4060-be39-46ee0620365d', '040f437a-eaf3-433c-be93-36008614769b', 'Quais competências ''humanas'' ganham destaque com a IA?', 'Inteligência emocional, criatividade, pensamento crítico, capacidade de resolução de problemas complexos, colaboração e adaptação a novas tecnologias.', '2026-03-03T20:27:43.128235+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0a938acb-8927-423d-b9f8-5b2cc90dd7e3', '040f437a-eaf3-433c-be93-36008614769b', 'Qual a importância da ''alfabetização digital e em IA'' para todos os profissionais hoje?', 'Permite que compreendam o funcionamento básico da IA, identifiquem seu potencial em suas áreas, utilizem ferramentas de forma eficaz e tomem decisões informadas sobre seu uso.', '2026-03-03T20:27:43.128235+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7ec8b98f-3c49-4229-b379-a49ed4669a64', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'O que são papéis de trabalho na auditoria operacional?', 'Papéis de trabalho são todos os documentos e registros que contêm as evidências coletadas, as análises realizadas, as conclusões e as opiniões do auditor, servindo de suporte para o relatório final.', '2026-03-12T20:31:23.405006+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a1b27224-64d5-420b-8787-8843ba403c96', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'Quais são os principais tipos de evidências?', 'Os principais tipos são evidências físicas (observação), documentais (registros, manuais), testemunhais (entrevistas), analíticas (cálculos, comparações) e eletrônicas (dados de sistemas).', '2026-03-12T20:31:23.405006+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ecc3f021-1b66-4088-9471-ee90c58a2f88', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'Qual a importância da amostragem na coleta de evidências?', 'A amostragem permite que o auditor examine uma parte representativa de uma população para inferir conclusões sobre o todo, otimizando o tempo e os recursos da auditoria.', '2026-03-12T20:31:23.405006+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('44731d3d-8e9a-47f3-acef-62af2e2023f6', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'Como garantir a validade das entrevistas como evidência?', 'Para garantir a validade, as entrevistas devem ser planejadas, registradas (com anuência do entrevistado), ter perguntas claras, e as informações obtidas devem ser corroboradas por outras evidências sempre que possível.', '2026-03-12T20:31:23.405006+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('53f43c56-2842-4aa1-b623-3d5c447b58a8', '1a75f8bf-312e-443e-8e67-9d15c8fdad76', 'O que significa ''testes de conformidade'' e ''testes substantivos'' na auditoria operacional?', 'Testes de conformidade avaliam se os controles internos estão funcionando conforme o esperado. Testes substantivos buscam evidências diretas sobre a eficácia, eficiência e economicidade dos processos.', '2026-03-12T20:31:23.405006+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('59a1480a-21f0-44b0-9d02-5b467b61db4e', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'Como a IA pode ser usada para otimizar o suporte ao cliente em uma empresa de software?', 'Através de chatbots que respondem a FAQs técnicas, ferramentas que analisam logs de erro para identificar causas comuns e sistemas que sugerem artigos de ajuda relevantes para o usuário.', '2026-03-03T20:27:49.630374+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('2bc4afd7-cd79-4716-8dd8-d49427cb094d', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'O que significa ''personalização em escala'' na experiência do cliente com IA?', 'Significa oferecer experiências customizadas e relevantes para um grande número de clientes individualmente, sem que isso demande um grande esforço manual para cada cliente.', '2026-03-03T20:27:49.630374+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('81ec1ade-786b-40ef-8e5d-b1836b64c8a7', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'Como a IA pode ajudar a identificar clientes com risco de churn (cancelamento)?', 'Analisando padrões de uso, frequência de interação, níveis de satisfação e histórico de problemas para prever quais clientes têm maior probabilidade de cancelar um serviço.', '2026-03-03T20:27:49.630374+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ae5882db-be18-434b-ad5a-87ee50b763a0', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'Quais são os benefícios para um profissional de vendas ao utilizar IA para entender melhor seus leads?', 'A IA pode fornecer insights sobre o engajamento do lead, identificar seus interesses e necessidades com base em suas interações, e sugerir a melhor abordagem de comunicação.', '2026-03-03T20:27:49.630374+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f7c484ad-926b-420e-a9b0-c9ba64d9dda2', '9097e6ed-030c-46fa-bf5b-a878ebb08302', 'Como a IA pode apoiar a criação de conteúdo mais engajador para um público específico?', 'Analisando o que o público já consome, quais temas geram mais interação e quais formatos são preferidos, permitindo a criação de conteúdo mais alinhado aos interesses.', '2026-03-03T20:27:49.630374+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('2016e783-df8e-42bf-a52e-29019a329713', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'O que é auditoria operacional?', 'Auditoria operacional é uma avaliação sistemática e independente da eficácia, eficiência e economicidade das operações de uma entidade ou programa, com o objetivo de identificar oportunidades de melhoria e agregar valor.', '2026-03-12T20:31:23.838837+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('1dfe0825-2735-4fc8-9eb8-c67544042713', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'Qual a distinção entre eficácia, eficiência e economicidade?', 'Eficácia refere-se ao alcance dos objetivos; Eficiência diz respeito à utilização dos recursos para alcançar os objetivos; Economicidade relaciona-se à aquisição de recursos com o menor custo e qualidade adequadas.', '2026-03-12T20:31:23.838837+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('1fcd69e4-2562-4ba9-baca-e7fcf593fa61', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'Por que a auditoria operacional é importante para a gestão pública?', 'Ela é importante para a gestão pública porque contribui para a melhoria do desempenho organizacional, aprimoramento da prestação de serviços públicos e o uso mais responsável e transparente dos recursos públicos.', '2026-03-12T20:31:23.838837+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('aaa3cc87-4ce9-44ef-84c8-f471704c50cc', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'Quais os principais usuários dos relatórios de auditoria operacional?', 'Os principais usuários são a alta administração da entidade auditada, órgãos de controle interno e externo, legisladores e a sociedade em geral interessada na boa governança.', '2026-03-12T20:31:23.838837+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('18f6cb1f-3736-4efb-a012-d6540a751375', '24a4b3e2-8cf2-4ef1-b72c-0dd8b261e7a8', 'Quais são os critérios de auditoria operacional?', 'Critérios de auditoria operacional são padrões ou marcos de referência pelos quais a entidade auditada pode ser avaliada, como leis, regulamentos, políticas internas, melhores práticas e objetivos estabelecidos.', '2026-03-12T20:31:23.838837+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b0771b93-8f86-4f68-a052-caf85ef50bf1', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'O que é um objeto de auditoria operacional?', 'O objeto de auditoria operacional é o processo, programa, sistema, atividade ou função da entidade que será avaliado pelo auditor, buscando identificar oportunidades de melhoria em sua gestão.', '2026-03-12T20:31:27.870302+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('460752bf-321f-4778-8fe7-268911fd5ac1', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'Qual a importância de um bom plano de auditoria?', 'Um bom plano de auditoria é fundamental para orientar a equipe, garantir que os objetivos sejam alcançados de forma eficaz e eficiente, e otimizar a alocação de recursos e tempo.', '2026-03-12T20:31:27.870302+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('1aae16ec-ddf2-4c49-a719-8bb1f2d6d7fe', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'O que é mapeamento de processos na auditoria operacional?', 'Mapeamento de processos é a representação visual e descritiva das etapas de um processo, suas entradas, saídas, responsáveis e controles, fundamental para compreender o funcionamento da área auditada.', '2026-03-12T20:31:27.870302+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('3e22afba-5674-4920-a12f-11e53b28b793', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'Como se define a equipe de auditoria operacional?', 'A equipe é definida com base nas qualificações e competências necessárias para auditar o objeto específico, considerando aspectos técnicos, de gestão e de comunicação, garantindo a multidisciplinaridade.', '2026-03-12T20:31:27.870302+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('bdd7206c-1f5d-4638-9a30-e2b802d506ee', 'daaeba13-7f7c-4d00-af51-d004d75028b1', 'Quais são as principais fontes de informação para o planejamento?', 'As principais fontes são leis e regulamentos, relatórios de auditorias anteriores, dados de desempenho, entrevistas com gestores e servidores, manuais de procedimentos e estrutura organizacional.', '2026-03-12T20:31:27.870302+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ad2a6795-0a6e-4b3a-83e2-1b2f36bdb178', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Como a IA pode ajudar a superar o bloqueio criativo em tarefas de escrita?', 'Oferecendo ideias, sugestões de tópicos e rascunhos para iniciar o processo criativo.', '2026-03-05T20:18:14.838195+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f0368f7b-44d2-41fc-a069-5fac3664cbf8', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Qual a importância da revisão humana ao usar IA para criação de conteúdo?', 'Garantir precisão, tom adequado, originalidade e alinhamento com os objetivos específicos.', '2026-03-05T20:18:14.838195+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('eb1af3d7-d831-4e13-b220-86f54d4c1a28', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Em que áreas de conteúdo escrito a IA pode ser aplicada com sucesso?', 'E-mails, relatórios, artigos de blog, descrições de produtos, posts de redes sociais, legendas, etc.', '2026-03-05T20:18:14.838195+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('380e14af-c12c-4881-91e3-0bce6a005e3b', 'dbdf15a1-6fae-4f6b-8f2a-a303aabcddba', 'Como a IA pode contribuir para a otimização de conteúdo para mecanismos de busca (SEO)?', 'Sugestões de palavras-chave, estrutura de texto e relevância semântica.', '2026-03-05T20:18:14.838195+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('84cf0d51-92fd-4dfb-94d0-42058817b9d6', '089da28e-7c78-427a-8f68-dffd82382e19', 'Qual é o propósito fundamental da Inteligência Artificial quando aplicada ao ambiente de trabalho?', 'Automatizar tarefas, otimizar processos e aumentar a eficiência geral.', '2026-03-05T20:18:15.04225+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('19994182-73aa-4e97-a443-9cae56506293', '089da28e-7c78-427a-8f68-dffd82382e19', 'Como a IA pode auxiliar profissionais não técnicos em suas rotinas?', 'Simplificando tarefas repetitivas, fornecendo insights e melhorando a tomada de decisão.', '2026-03-05T20:18:15.04225+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b6441d14-c8bf-488e-9b7a-08a5bf3f1564', '089da28e-7c78-427a-8f68-dffd82382e19', 'Cite um exemplo de tarefa de escritório que a IA pode automatizar.', 'Organização de e-mails, agendamento de reuniões ou classificação de documentos.', '2026-03-05T20:18:15.04225+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e86784f2-a571-4888-854b-953fd30de98e', '089da28e-7c78-427a-8f68-dffd82382e19', 'O que significa o termo ''automação de tarefas'' no contexto da IA?', 'Utilizar sistemas inteligentes para executar atividades sem intervenção humana direta.', '2026-03-05T20:18:15.04225+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c7a77a39-c061-44ad-b8c4-91abb8b2bb39', '089da28e-7c78-427a-8f68-dffd82382e19', 'Quais são os principais tipos de IA que você pode encontrar no mercado hoje?', 'Aprendizado de máquina (Machine Learning), Processamento de Linguagem Natural (PLN) e Visão Computacional.', '2026-03-05T20:18:15.04225+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('8ecee773-6979-48fd-93ff-39ee69453910', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'Que tipo de IA é amplamente utilizado para gerenciar e organizar e-mails?', 'Processamento de Linguagem Natural (PLN) para entender o conteúdo e classificá-lo.', '2026-03-05T20:18:15.133144+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7aadd7fa-dae7-4d50-8ad0-d82f49673d29', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'Como uma ferramenta de IA pode otimizar o agendamento de reuniões com participantes em diferentes locais?', 'Analisa calendários compartilhados e fuso horários para encontrar horários mutuamente convenientes.', '2026-03-05T20:18:15.133144+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d3575012-dfc9-4c6e-83da-04cbb214f29a', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'Qual o benefício de usar IA para resumir documentos longos?', 'Economiza tempo ao apresentar os pontos chave e informações essenciais de forma concisa.', '2026-03-05T20:18:15.133144+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('62a7372d-b600-40e5-ac6f-139d519b3be4', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'O que são ''assistentes virtuais'' no contexto da gestão de comunicação?', 'Programas que utilizam IA para interagir com usuários, responder a perguntas e executar tarefas como agendamento e envio de e-mails.', '2026-03-05T20:18:15.133144+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('1c373bf9-e2c5-45b8-bcf8-561001a6a40c', 'fce64ee1-61a2-4040-b4dd-ce7bad4d8435', 'Como a IA pode ajudar na gestão de grandes volumes de documentos?', 'Através da indexação inteligente, busca semântica e categorização automática.', '2026-03-05T20:18:15.133144+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('df439e73-da7f-44cc-a37d-420f9440ac83', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'Como a IA pode identificar tendências em dados de vendas?', 'Analisando padrões de compra, sazonalidade, comportamento do consumidor e fatores externos.', '2026-03-05T20:18:37.545245+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('694925e5-2527-4810-bc99-b1db1b45dc55', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'Qual a principal vantagem de usar IA para criar relatórios de análise de dados?', 'Acelera a geração de insights, identifica correlações e sumariza informações complexas.', '2026-03-05T20:18:37.545245+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('35c4bcb8-5aaf-4eda-8747-f66288462619', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'O que significa ''análise preditiva'' no contexto da IA e negócios?', 'Utilizar dados históricos para prever resultados futuros, como demanda de produtos ou comportamento do cliente.', '2026-03-05T20:18:37.545245+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('6db8b069-e841-4ba4-b1ff-efddf9cc190b', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'Que tipo de IA é frequentemente usado para classificação de dados em categorias?', 'Algoritmos de Machine Learning, como árvores de decisão ou redes neurais.', '2026-03-05T20:18:37.545245+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b30a8b5a-34d5-4ac4-bc5f-60487bf37f3c', '4198754b-f3d8-42b8-934c-0dea27315bb1', 'Como a IA pode ajudar a detectar fraudes em transações financeiras?', 'Identificando padrões de comportamento incomuns ou suspeitos que desviam do normal.', '2026-03-05T20:18:37.545245+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('5897059f-d592-468b-b3fc-a38df9ff9aa6', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'Como a IA pode otimizar a alocação de recursos em um projeto?', 'Analisando a disponibilidade, habilidades e carga de trabalho das equipes para sugerir a melhor distribuição.', '2026-03-05T20:18:41.107049+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('fac66d29-e1a8-466f-98a9-8b4009a8c769', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'Qual benefício a IA traz para a gestão de tarefas diárias?', 'Ajuda a priorizar, organizar e lembrar de prazos, aumentando a eficiência pessoal.', '2026-03-05T20:18:41.107049+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('87897cc4-c719-4cce-9d08-ff1466024762', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'O que significa ''agendamento dinâmico'' em ferramentas de gestão de projetos com IA?', 'A capacidade de ajustar e reorganizar cronogramas automaticamente com base em novas informações ou imprevistos.', '2026-03-05T20:18:41.107049+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d98749a5-5c2a-4e70-bdb9-3f40dd9b6e93', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'Como a IA pode auxiliar na identificação de dependências entre tarefas?', 'Mapeando as relações lógicas entre atividades, indicando quais precisam ser concluídas antes que outras comecem.', '2026-03-05T20:18:41.107049+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('216015e6-665e-42c4-8c89-ab976b7568c2', 'd847b2a2-cf44-40c2-96c8-61763e86de12', 'Que tipo de IA é utilizado para prever a duração de tarefas em um projeto?', 'Machine Learning, analisando dados de projetos anteriores e características da tarefa.', '2026-03-05T20:18:41.107049+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('6049ec8c-c1a3-4d0f-a74a-e06cc6b4cf81', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'Quais são os principais riscos de segurança associados ao uso de IA no trabalho?', 'Vazamento de dados, ataques cibernéticos direcionados, manipulação de algoritmos.', '2026-03-05T20:18:42.36731+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('63a6dd9e-4b4c-4dcb-9603-3b5afe468bb6', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'Como mitigar o viés algorítmico em sistemas de IA?', 'Garantindo diversidade nos dados de treinamento, auditando algoritmos regularmente e estabelecendo diretrizes éticas claras.', '2026-03-05T20:18:42.36731+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('6611f455-5e3f-4372-be9f-585040bb5aff', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'O que são ''LGPD'' e ''GDPR'' no contexto da IA e dados?', 'Leis de proteção de dados (Lei Geral de Proteção de Dados - Brasil, General Data Protection Regulation - Europa) que regulam o tratamento de informações pessoais.', '2026-03-05T20:18:42.36731+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('85f8066f-390f-42e1-9c18-d0f35b33b407', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'Qual a responsabilidade do usuário ao implementar ferramentas de IA?', 'Compreender suas limitações, utilizá-las de forma ética e garantir a segurança das informações manuseadas.', '2026-03-05T20:18:42.36731+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e7e277e8-457d-456c-92b5-c47c697200b3', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'Como garantir a transparência no uso de IA no trabalho?', 'Quando possível, explicar como a IA toma decisões e quais dados são utilizados, promovendo a confiança.', '2026-03-05T20:18:42.36731+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0ca7f747-d998-4087-8dd7-bff12ec2d3be', '6652a578-9328-4d81-a51a-5cef002b123f', 'Quais são os passos essenciais para implementar uma nova ferramenta de IA em um ambiente de trabalho?', 'Análise de necessidades, seleção da ferramenta, treinamento, implementação piloto e avaliação contínua.', '2026-03-05T20:19:09.656962+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('5d65dedd-7ab4-4897-bfdf-34f1b892b8b0', '6652a578-9328-4d81-a51a-5cef002b123f', 'Como a IA pode apoiar um modelo de trabalho híbrido ou remoto?', 'Facilitando a colaboração, organização de tarefas e comunicação assíncrona.', '2026-03-05T20:19:09.656962+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0748a478-f06b-42d1-9c5a-4d2e5b4e69b5', '6652a578-9328-4d81-a51a-5cef002b123f', 'Qual o papel do aprendizado contínuo em um mundo impulsionado pela IA?', 'Manter-se atualizado com novas ferramentas e capacidades da IA para otimizar constantemente a produtividade.', '2026-03-05T20:19:09.656962+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f362b5b9-312f-4216-b3ea-fdf5349f8ca9', '6652a578-9328-4d81-a51a-5cef002b123f', 'Como avaliar o sucesso da implementação de uma ferramenta de IA?', 'Medindo métricas de produtividade, eficiência, redução de custos e satisfação dos usuários.', '2026-03-05T20:19:09.656962+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('664b0c25-58fe-4574-ad06-8bcdf80f935d', '6652a578-9328-4d81-a51a-5cef002b123f', 'Qual a perspectiva para a colaboração entre humanos e IA no futuro do trabalho?', 'Uma simbiose crescente, onde a IA aumenta as capacidades humanas e vice-versa, otimizando resultados.', '2026-03-05T20:19:09.656962+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('edd219a5-fd44-4f88-b80b-7f3e47cb6189', 'ad899c16-05d0-42b1-956c-90a067c54081', 'O que é um tipo de dado primitivo em programação?', 'Um tipo de dado primitivo é um tipo de dado básico, não composto, que representa valores simples como números, caracteres ou valores booleanos.', '2026-03-11T17:37:19.447086+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b165919c-1067-47ed-a705-b94241eba099', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Qual a diferença entre um operador aritmético e um operador lógico?', 'Operadores aritméticos realizam cálculos matemáticos (soma, subtração), enquanto operadores lógicos combinam ou avaliam expressões booleanas (AND, OR, NOT).', '2026-03-11T17:37:19.447086+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f54582f1-3853-4e89-8783-f9500551733a', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Por que a escolha correta do tipo de dado para uma variável é importante?', 'A escolha correta do tipo de dado garante a eficiência do programa, evita erros de arredondamento ou overflow, e assegura que os dados sejam armazenados da maneira mais adequada.', '2026-03-11T17:37:19.447086+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a094ac22-993e-44d3-908a-ba595b5b282c', 'ad899c16-05d0-42b1-956c-90a067c54081', 'O que um operador de comparação como ''>'' verifica?', 'Um operador de comparação como ''>'' verifica se o valor à esquerda é estritamente maior que o valor à direita, resultando em um valor booleano (verdadeiro ou falso).', '2026-03-11T17:37:19.447086+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7ada9866-ec62-4c60-b721-d49104abc589', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Como uma variável do tipo booleano pode ser utilizada?', 'Uma variável booleana pode ser utilizada para representar estados de sim/não, verdadeiro/falso, ou para controlar o fluxo de execução de um programa com base em condições.', '2026-03-11T17:37:19.447086+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('adc7eb45-a30d-47cd-885d-ae0910135695', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Qual o propósito de usar estruturas condicionais em um programa?', 'Estruturas condicionais permitem que um programa tome decisões e execute diferentes caminhos de código com base em se certas condições são verdadeiras ou falsas.', '2026-03-11T17:37:26.325609+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7bb26c4e-91f7-42d4-bf08-93f727c7f019', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Em que cenário a estrutura ''else'' sem um ''if'' anterior seria utilizada?', 'Um bloco ''else'' sempre precisa de um ''if'' ou ''else if'' correspondente; ele representa o caminho a ser seguido caso todas as condições anteriores (do ''if'' e ''else if''s) sejam falsas.', '2026-03-11T17:37:26.325609+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7e5325e3-a5cc-4c31-a425-a8ea0174e10b', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Como a estrutura condicional ''if-else if-else'' ajuda na organização do código?', 'Ela ajuda a organizar o código ao permitir a avaliação sequencial de múltiplas condições, garantindo que apenas um caminho de código específico seja executado com base na primeira condição verdadeira.', '2026-03-11T17:37:26.325609+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7d7bc64b-ae8d-4dd3-b6ed-02886b696d5b', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'O que significa uma condição ser ''verdadeira'' em um contexto de programação?', 'Uma condição é considerada ''verdadeira'' quando a expressão avaliada resulta em um valor que indica que a afirmação é correta, o que geralmente é representado por um valor booleano ''true''.', '2026-03-11T17:37:26.325609+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e3959e4c-89c8-4753-bf3d-9140283c2ed1', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Qual o impacto direto de condições mal formuladas em estruturas de controle de fluxo?', 'Condições mal formuladas podem levar a um comportamento inesperado do programa, onde caminhos de código serão executados incorretamente ou não serão executados quando deveriam, resultando em bugs.', '2026-03-11T17:37:26.325609+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0ce2f5db-4dd5-4b57-9b81-0a5636ff7d27', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Qual o principal objetivo de se utilizar algoritmos no desenvolvimento de software?', 'O principal objetivo é fornecer um conjunto de instruções passo a passo bem definidas para resolver um problema específico ou realizar uma tarefa.', '2026-03-11T17:37:29.599728+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7c513f64-e6da-4d7f-8a0f-ed3e7c781ecc', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Como um fluxograma auxilia na criação de um algoritmo?', 'Um fluxograma auxilia visualmente na organização das etapas e no entendimento do fluxo de decisões, tornando mais fácil projetar e depurar a lógica antes da codificação.', '2026-03-11T17:37:29.599728+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b19f7a78-3213-4a42-8b51-cbaa2ba2ec0c', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Quando o pseudocódigo é mais vantajoso em comparação com um fluxograma?', 'O pseudocódigo é mais vantajoso quando se deseja uma descrição textual detalhada que é mais fácil de escrever e modificar para algoritmos complexos, além de ser mais próximo da sintaxe de linguagens de programação.', '2026-03-11T17:37:29.599728+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('9d405e6c-5085-4d80-8801-5592e84214a4', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Que tipo de problema a lógica computacional busca resolver?', 'A lógica computacional busca resolver problemas de forma estruturada e sequencial, decompondo-os em etapas menores que um computador pode processar.', '2026-03-11T17:37:29.599728+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7ec19368-8000-4820-bc16-18ae201136e3', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Qual a diferença fundamental entre um algoritmo e um programa de computador?', 'Um algoritmo é a descrição lógica e conceitual de uma solução, enquanto um programa de computador é a implementação desse algoritmo em uma linguagem de programação específica.', '2026-03-11T17:37:29.599728+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a5ba10f6-7e39-415a-8ece-bf0bcf0fbc96', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Qual a principal diferença entre o loop ''for'' e o loop ''while''?', 'O loop ''for'' é geralmente usado quando o número de iterações é conhecido ou pode ser facilmente determinado, enquanto o loop ''while'' é usado quando a iteração continua enquanto uma condição for verdadeira.', '2026-03-11T17:37:59.664217+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f089b71c-3c49-4985-968e-f7b1104998ee', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Como um loop pode ser usado para processar todos os elementos de uma lista?', 'Um loop pode iterar sobre cada elemento de uma lista, permitindo que uma ação seja realizada individualmente em cada item (por exemplo, para exibir, modificar ou somar).', '2026-03-11T17:37:59.664217+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('50f7ca65-9caf-41a1-a69f-58ef81530de1', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'O que pode acontecer se a condição de um loop ''while'' nunca se tornar falsa?', 'Se a condição de um loop ''while'' nunca se tornar falsa, o programa entrará em um loop infinito, executando o bloco de código repetidamente sem parar, o que pode travar a aplicação.', '2026-03-11T17:37:59.664217+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('385d927a-d44b-4931-9159-34e55ae06c8d', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Qual é o propósito das palavras-chave ''break'' e ''continue'' dentro de um loop?', '''break'' sai completamente do loop, enquanto ''continue'' pula a iteração atual e prossegue para a próxima iteração do loop.', '2026-03-11T17:37:59.664217+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('469be4dd-a0dd-4379-b39e-df738c83b12a', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Como a contagem de iterações é gerenciada em um loop ''for'' padrão?', 'Em um loop ''for'' padrão, a contagem de iterações é gerenciada por um contador que é inicializado, comparado a uma condição e incrementado/decrementado em cada passagem.', '2026-03-11T17:37:59.664217+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('cec1c01d-07ba-41de-a8f4-1423bfebb9e1', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Qual o benefício de modularizar o código usando funções?', 'Modularizar o código em funções torna-o mais organizado, legível, fácil de testar, depurar e reutilizar em diferentes partes do programa ou em outros projetos.', '2026-03-11T17:38:06.238353+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('740aa2c9-feab-4fec-89a7-e0b5866291c0', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'O que significa ''escopo de uma variável'' em relação a funções?', 'O escopo de uma variável refere-se à área do programa onde essa variável é válida e pode ser acessada. Variáveis definidas dentro de uma função geralmente têm escopo local.', '2026-03-11T17:38:06.238353+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('787c5b64-20b1-447d-ae81-56e8fcaf70a8', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Como uma função pode modificar o estado de uma variável externa a ela?', 'Isso geralmente é feito passando a variável por referência (dependendo da linguagem) ou, mais comumente, a função retorna um novo valor que é então atribuído à variável externa.', '2026-03-11T17:38:06.238353+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4ce51199-c075-4b07-871a-77952673bcaa', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Por que funções que recebem parâmetros são consideradas mais flexíveis?', 'Elas são mais flexíveis porque podem realizar a mesma tarefa em diferentes conjuntos de dados, sem a necessidade de reescrever o código para cada conjunto de dados.', '2026-03-11T17:38:06.238353+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('eeddfbdb-9941-4233-a7dd-681f34383e84', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Qual a importância de dar nomes descritivos a funções?', 'Nomes descritivos ajudam os programadores a entender rapidamente qual tarefa uma função realiza, melhorando a manutenção e a colaboração no desenvolvimento.', '2026-03-11T17:38:06.238353+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('42c963cb-ace2-4b12-804c-fde732a4e1b7', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'O que significa ''Condição'' em um achado de auditoria?', '''Condição'' é a situação atual observada pelo auditor, a forma como os processos ou atividades estão sendo realizados na prática.', '2026-03-12T20:32:21.409616+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('5990b0fc-301f-42c5-9d91-7ac82f275005', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'O que é ''Critério'' em um achado de auditoria?', '''Critério'' são os padrões, normas, leis, regulamentos, boas práticas ou objetivos que deveriam ser seguidos ou alcançados pela entidade.', '2026-03-12T20:32:21.409616+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c9f4efc8-7b0f-4a2a-ac4d-fd31ce7ec8b5', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'Qual a relevância da ''Causa'' de um achado?', 'A ''Causa'' é a razão pela qual a condição difere do critério; identificá-la é crucial para elaborar recomendações que resolvam o problema na sua origem e evitem a reincidência.', '2026-03-12T20:32:21.409616+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('db5cde96-319c-45ce-8083-6464a1130a25', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'O que representa o ''Efeito'' de um achado?', 'O ''Efeito'' descreve as consequências negativas ou o impacto (financeiro, social, de imagem, de desempenho) decorrente da condição atual em relação ao critério.', '2026-03-12T20:32:21.409616+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('44dce0b7-4e96-486e-a422-a1be980f664b', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'Como garantir que as recomendações sejam implementáveis?', 'Para garantir a implementabilidade, as recomendações devem ser discutidas com a gestão, considerar os recursos disponíveis, ser claras, específicas e, sempre que possível, ter metas e prazos definidos.', '2026-03-12T20:32:21.409616+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a18524d8-e25b-49da-939b-0a8514705ae8', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Quais os elementos essenciais de um relatório de auditoria operacional?', 'Elementos essenciais incluem resumo executivo, introdução (objetivo, escopo), metodologia, achados detalhados (Condição, Critério, Causa, Efeito), recomendações, e a manifestação da gestão.', '2026-03-12T20:32:24.828105+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('2a6afd2a-7f3b-44af-8aa4-5522e576ffbb', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Por que a clareza na linguagem é vital no relatório?', 'A clareza na linguagem é vital para que o relatório seja compreendido por diversos públicos, incluindo não-especialistas, facilitando a aceitação e a implementação das recomendações.', '2026-03-12T20:32:24.828105+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('884d55d5-4331-465b-8b18-e9ba66bbfe5c', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'O que é um plano de ação na fase de monitoramento?', 'O plano de ação é um documento elaborado pela entidade auditada, em resposta às recomendações, detalhando as ações a serem tomadas, os responsáveis e os prazos para implementação de cada recomendação.', '2026-03-12T20:32:24.828105+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('526a2052-5fef-4ebd-b37b-bd295223084e', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Qual a importância da apresentação dos resultados à gestão?', 'A apresentação dos resultados à gestão é crucial para promover o debate, esclarecer dúvidas, obter o comprometimento dos gestores com as recomendações e iniciar o processo de melhoria.', '2026-03-12T20:32:24.828105+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('de138a10-c23c-4904-a44d-17c2b55c52c0', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Quais são os desafios do monitoramento de recomendações?', 'Os desafios incluem a resistência à mudança, a falta de recursos para implementação, a dificuldade em medir o impacto das ações e a necessidade de comunicação contínua entre auditores e auditados.', '2026-03-12T20:32:24.828105+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('de3a5eab-ebd3-4224-9b4b-7283a4d6bcb3', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'O que significa ''índice zero'' ao acessar elementos de um array?', 'Significa que o primeiro elemento de um array é sempre acessado usando o índice ''0'', o segundo com ''1'', e assim por diante.', '2026-03-11T17:38:07.296934+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('da84c1a8-1390-44d4-ad29-c1faeca0149b', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'Como você adicionaria um novo elemento ao final de uma lista em programação?', 'Geralmente, utiliza-se um método específico da lista, como ''append()'' ou ''add()'', dependendo da linguagem de programação.', '2026-03-11T17:38:07.296934+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('55124599-b542-4929-b679-a82883864df1', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'Qual a vantagem de usar arrays ou listas para armazenar múltiplos valores?', 'A vantagem é a organização e a capacidade de gerenciar coleções de dados de forma eficiente, permitindo operações sobre todos os elementos de maneira estruturada.', '2026-03-11T17:38:07.296934+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('cc25f7dd-8a5c-4ca0-9ef2-f388e30b9f74', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'Como é feita a iteração (percorrer) sobre todos os elementos de um array ou lista?', 'A iteração é feita tipicamente usando loops (como ''for'' ou ''while'') que acessam cada elemento com base no seu índice ou por meio de um iterador.', '2026-03-11T17:38:07.296934+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('baa016e4-769c-4514-8ad0-b09962691eed', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'O que acontece se você tentar acessar um índice que não existe em um array (fora dos limites)?', 'O programa geralmente gerará um erro, como ''IndexOutOfBoundsException'' ou similar, indicando que o índice solicitado está fora do intervalo válido do array.', '2026-03-11T17:38:07.296934+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('27786d27-073f-4e1e-a8b1-b2d234e76eb6', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'O que significa ''código limpo'' (clean code)?', 'Código limpo é aquele que é fácil de ler, entender, modificar e manter por outros desenvolvedores (ou por você mesmo no futuro).', '2026-03-11T17:38:59.991028+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('194877e0-04e8-4fb7-87fe-7a6edf03f28f', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Qual a regra geral para quando escrever comentários em código?', 'Comente o ''porquê'' e não o ''o quê''. Se o código é autoexplicativo, um comentário pode ser desnecessário. Comente quando a lógica for complexa, incomum ou tiver um propósito específico.', '2026-03-11T17:38:59.991028+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e5b9321d-3b48-485c-a64c-2a3df6ecdad4', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Por que se deve evitar nomes de variáveis ambíguos ou genéricos?', 'Nomes ambíguos ou genéricos dificultam a compreensão do que a variável representa ou armazena, levando a erros de interpretação e bugs.', '2026-03-11T17:38:59.991028+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ff4e8b29-05b0-4c51-bae2-1b272d173eb7', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Como a consistência na codificação contribui para a legibilidade?', 'A consistência em estilos de escrita (indentação, nomenclatura, formatação) cria um padrão reconhecível em todo o código, tornando-o mais previsível e fácil de seguir.', '2026-03-11T17:38:59.991028+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('005f4553-b621-4396-b882-ee0a6cef5188', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Qual o risco de escrever código excessivamente complexo em vez de soluções mais simples?', 'Código excessivamente complexo é mais propenso a erros, mais difícil de entender e manter, e pode levar a problemas de performance não intencionais.', '2026-03-11T17:38:59.991028+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ce77d263-3521-4ed0-80cf-5e1a6b1d0c0a', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Qual é o objetivo principal ao se iniciar um projeto prático de programação?', 'O objetivo principal é aplicar e integrar os conhecimentos teóricos adquiridos, desenvolvendo a capacidade de resolver problemas de forma prática e autônoma.', '2026-03-11T17:39:01.896527+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('57ce84fb-cb57-444e-802a-582484a2c033', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Quais ferramentas são essenciais para o desenvolvimento de software, além de um editor de código?', 'Um sistema de controle de versão (como Git), um compilador/interpretador da linguagem escolhida, e possivelmente um ambiente de desenvolvimento integrado (IDE) são muito importantes.', '2026-03-11T17:39:01.896527+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('962aaa21-1321-42b5-9d18-54bb1707282e', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Como lidar com erros e bugs que surgem durante o desenvolvimento de um projeto?', 'Erros e bugs são normais. É importante aprender a ler mensagens de erro, utilizar ferramentas de depuração, pesquisar online e, se necessário, pedir ajuda a outros desenvolvedores.', '2026-03-11T17:39:01.896527+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('764b5d15-35c2-4e9e-a837-b8f99c6ccf82', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Qual a importância de um sistema de controle de versão (como Git) em projetos maiores?', 'Sistemas de controle de versão permitem rastrear todas as alterações feitas no código, colaborar com múltiplos desenvolvedores em um mesmo projeto e reverter para versões anteriores se algo der errado.', '2026-03-11T17:39:01.896527+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('05ab2c8c-522e-4f87-8f3f-b128b34926fc', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Quais são exemplos de próximos passos após dominar os fundamentos da programação?', 'Explorar linguagens de programação mais avançadas, aprender sobre frameworks específicos (web, mobile), sistemas operacionais, bancos de dados ou inteligência artificial.', '2026-03-11T17:39:01.896527+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('1899ff8d-b54f-4fe6-905d-3e387b5ba451', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Qual o papel dos blocos ''if'' e ''else''?', 'O bloco ''if'' executa código se uma condição for verdadeira, enquanto o bloco ''else'' executa código se a condição do ''if'' for falsa.', '2026-03-11T17:47:00.54138+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a803305a-e3f3-4c4e-930f-6f0c72b5e2e4', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Como funciona a estrutura ''if-else if-else''?', 'Ela permite verificar uma série de condições sequencialmente. A primeira condição verdadeira aciona seu bloco de código, e as demais são ignoradas. O ''else'' final é executado se nenhuma condição anterior for verdadeira.', '2026-03-11T17:47:00.54138+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a49f45ef-880d-453a-b096-1b733fcc08cd', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'O que significa ''tomar decisões'' em um programa?', 'Significa que o programa pode alterar seu fluxo de execução com base em diferentes condições, escolhendo caminhos distintos para resolver um problema ou responder a inputs.', '2026-03-11T17:47:00.54138+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f7358578-ca45-4c27-a3e8-fc4ab5b0db68', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Quando devo usar operadores lógicos (AND, OR, NOT) dentro de uma condição?', 'Você usa operadores lógicos para combinar múltiplas condições booleanas em uma única instrução condicional, permitindo verificações mais complexas.', '2026-03-11T17:47:00.54138+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b1b4babd-8da1-4b33-8cce-0e0dc131eec2', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Qual o resultado da comparação ''10 > 5'' dentro de um ''if''?', 'O resultado é ''verdadeiro'' (true), portanto, o código dentro do bloco ''if'' seria executado.', '2026-03-11T17:47:00.54138+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('999b7c03-ee77-40c7-932b-54af4dda4c53', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Qual é a definição de um algoritmo em programação?', 'Um algoritmo é uma sequência finita e ordenada de instruções claras e não ambíguas, projetada para resolver um problema específico ou realizar uma tarefa.', '2026-03-11T17:47:00.656081+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('170bd439-c657-4300-8c0d-0d774dd7f703', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Para que servem os fluxogramas?', 'Fluxogramas são diagramas que representam visualmente o fluxo lógico de um processo ou algoritmo, utilizando símbolos padronizados para indicar operações, decisões e pontos de início/fim.', '2026-03-11T17:47:00.656081+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('44491eaa-ea04-4bd3-a0c0-1d50d6cf8f8c', '8e92b920-5447-4356-9e40-294db76d7fe6', 'O que significa um algoritmo ser ''finito''?', 'Significa que o algoritmo deve sempre terminar após um número limitado de passos, não entrando em um ciclo infinito de operações.', '2026-03-11T17:47:00.656081+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0136fa73-6687-4dc8-b439-1a2a182b1c69', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Qual a diferença entre pseudocódigo e linguagem de programação?', 'O pseudocódigo é uma descrição informal de um algoritmo, em linguagem natural e com algumas convenções de programação, enquanto a linguagem de programação é formal e pode ser entendida por computadores.', '2026-03-11T17:47:00.656081+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('099cb61a-9699-4687-8228-c8e29e4782f9', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Como a lógica computacional ajuda na resolução de problemas?', 'A lógica computacional decompõe problemas complexos em etapas menores e sequenciais, permitindo a criação de soluções estruturadas e eficientes através de algoritmos.', '2026-03-11T17:47:00.656081+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4722db25-96f2-470b-b635-67df76192a51', '511afd44-edc1-487e-bd88-d4399ec3351b', 'O que é uma variável em programação?', 'Uma variável é um espaço na memória do computador que armazena um valor, identificado por um nome, e cujo valor pode ser alterado durante a execução do programa.', '2026-03-11T17:47:00.943288+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d6b55669-2c9d-47bf-b974-eae6e300f1e1', '511afd44-edc1-487e-bd88-d4399ec3351b', 'Quais são alguns exemplos de tipos de dados básicos?', 'Exemplos incluem Integer (números inteiros), Float/Double (números decimais), String (texto) e Boolean (verdadeiro/falso).', '2026-03-11T17:47:00.943288+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('501ab143-a14d-4fdc-872d-e127b654ff25', '511afd44-edc1-487e-bd88-d4399ec3351b', 'Para que servem os operadores aritméticos?', 'Operadores aritméticos realizam operações matemáticas como adição (+), subtração (-), multiplicação (*), divisão (/) e módulo (%).', '2026-03-11T17:47:00.943288+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('1dbfcb6f-a9cb-45df-8b20-b79e8e5c1bc2', '511afd44-edc1-487e-bd88-d4399ec3351b', 'O que um operador relacional compara?', 'Operadores relacionais comparam dois valores e retornam um resultado booleano (verdadeiro ou falso), como maior que (>), menor que (<), igual a (==) e diferente de (!=).', '2026-03-11T17:47:00.943288+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e682a32a-c625-4de5-9560-043769addb7a', '511afd44-edc1-487e-bd88-d4399ec3351b', 'Explique o tipo de dado ''Boolean''.', 'O tipo de dado Boolean representa valores lógicos, podendo ser apenas ''verdadeiro'' (true) ou ''falso'' (false), frequentemente usado em condições e comparações.', '2026-03-11T17:47:00.943288+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('01c02919-eeae-46ac-8c77-256c42816d0f', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Qual a principal diferença entre ''for'' e ''while''?', 'O ''for'' é geralmente usado quando o número de iterações é conhecido antecipadamente, enquanto o ''while'' é mais flexível e executa enquanto uma condição for verdadeira, sem necessariamente saber o número exato de repetições.', '2026-03-11T17:47:32.859846+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c4635b72-eaf7-48ea-aba9-8a4d6689de9b', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'O que significa ''iterar''?', 'Iterar significa repetir um conjunto de instruções ou operações. Em loops, cada repetição é uma iteração.', '2026-03-11T17:47:32.859846+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d1b5fc90-92ab-4ea2-bd5c-cb6d83d120bd', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Quais são os componentes típicos de um loop ''for''?', 'Um loop ''for'' comumente inclui a inicialização de um contador, uma condição de parada e uma expressão de atualização (incremento ou decremento do contador).', '2026-03-11T17:47:32.859846+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('13490b3f-7962-4837-8678-37327d3ee0d9', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Como garantir que um loop ''while'' termine?', 'É essencial ter uma lógica dentro do loop que, em algum momento, altere o estado de forma que a condição de parada do ''while'' se torne falsa.', '2026-03-11T17:47:32.859846+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('12af0962-745e-4d9b-ad72-bad457edd7e6', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Qual o risco de um loop infinito?', 'Um loop infinito pode consumir todos os recursos do processador, levar o programa a travar e, em alguns casos, exigir o reinício do sistema.', '2026-03-11T17:47:32.859846+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('40f0aabe-29ea-4af3-bc70-54231d320d5a', 'f59c5f35-c986-4791-97ff-1681c531742a', 'O que é um array e para que serve?', 'Um array é uma estrutura de dados que armazena múltiplos valores (geralmente do mesmo tipo) sob um único nome, acessados por um índice numérico.', '2026-03-11T17:47:39.530592+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('da511dea-357a-4571-898d-05cb75739c8e', 'f59c5f35-c986-4791-97ff-1681c531742a', 'Como se acessa um elemento em um array?', 'Um elemento é acessado utilizando o nome do array seguido do índice do elemento entre colchetes, por exemplo, ''meuArray[2]''.', '2026-03-11T17:47:39.530592+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('42a15821-232d-4adf-ba35-68a998c8aed5', 'f59c5f35-c986-4791-97ff-1681c531742a', 'Qual a diferença entre um array estático e uma lista dinâmica?', 'Arrays estáticos têm um tamanho fixo definido em tempo de criação, enquanto listas dinâmicas podem mudar de tamanho (crescer ou diminuir) durante a execução do programa.', '2026-03-11T17:47:39.530592+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0df8c304-fdc4-4308-9a1c-ba781301b65e', 'f59c5f35-c986-4791-97ff-1681c531742a', 'O que significa ''index out of bounds'' (índice fora dos limites)?', 'Ocorre quando se tenta acessar um elemento de um array usando um índice que não existe, ou seja, menor que 0 ou maior ou igual ao tamanho do array.', '2026-03-11T17:47:39.530592+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e3f0b7b2-d9ab-4faa-8627-6b1288f7bba4', 'f59c5f35-c986-4791-97ff-1681c531742a', 'Como podemos percorrer todos os elementos de um array?', 'Geralmente usamos um loop (como ''for'' ou ''while'') que itera do índice 0 até o último índice válido do array, acessando cada elemento em cada iteração.', '2026-03-11T17:47:39.530592+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('5ee638a4-86a8-43be-99b5-7f82086553ee', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'O que é uma função em programação?', 'Uma função é um bloco de código nomeado que realiza uma tarefa específica. Pode receber dados como entrada (parâmetros), processá-los e, opcionalmente, retornar um resultado.', '2026-03-11T17:47:42.280753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ea8aa66d-f517-4b8d-9ac4-6fcbbc01c0d3', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'Por que a reutilização de código é importante?', 'Reutilizar código economiza tempo e esforço, reduz a chance de erros (já que o código testado é reaproveitado) e torna o programa mais fácil de manter e entender.', '2026-03-11T17:47:42.280753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7768cb1f-7587-4245-b52a-39bd246317b8', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'O que são argumentos de uma função?', 'Argumentos são os valores reais passados para uma função quando ela é chamada. Estes valores são atribuídos aos parâmetros definidos na função.', '2026-03-11T17:47:42.280753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('604bf3da-39c6-4ec3-bac1-6f248a119860', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'Uma função pode ou não retornar um valor? Explique.', 'Sim. Algumas funções realizam uma ação (como imprimir algo na tela) e não precisam retornar um valor específico. Outras calculam um valor e usam a instrução ''return'' para devolvê-lo.', '2026-03-11T17:47:42.280753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d987b2ee-6a5d-419e-8d80-00fcb897cb04', '9b1bc747-62d3-4f6a-b52c-2341517c3313', 'Como a modularidade melhora o desenvolvimento de software?', 'Modularidade divide um programa grande em partes menores e independentes (módulos/funções), tornando o desenvolvimento, teste e manutenção mais fáceis e eficientes.', '2026-03-11T17:47:42.280753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4f34f877-1d69-46ad-a246-218477dc65db', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'O que significa ''código limpo'' (clean code)?', 'Código limpo é aquele que é fácil de ler, entender, manter e modificar, seguindo princípios de clareza, simplicidade e organização.', '2026-03-11T17:48:22.700153+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('86dbfc53-a3be-4f0b-a326-a716fb46ee73', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'Por que nomes descritivos são importantes?', 'Nomes claros e sugestivos ajudam a entender a intenção do código sem precisar ler toda a lógica. Evitam confusão e facilitam a depuração e a colaboração.', '2026-03-11T17:48:22.700153+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('3de9f6f9-2063-45a3-8b43-5a69e57e57db', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'Como a identação afeta a qualidade do código?', 'Uma identação consistente e correta melhora dramaticamente a legibilidade, destacando a estrutura lógica do código (níveis de aninhamento, blocos de controle, etc.).', '2026-03-11T17:48:22.700153+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('05b5b16c-76d9-4bb3-a06f-ba0fa2e951ba', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'Quando usar comentários?', 'Use comentários para explicar o raciocínio complexo, intenções não óbvias, ou para documentar decisões de design. Evite comentar o óbvio.', '2026-03-11T17:48:22.700153+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('02eee9e6-dfc0-40f8-adfd-cde86b3bf8ad', 'bb82f31c-f5a2-4757-b89d-e788b3f0d904', 'Qual a regra geral para convenções de nomenclatura?', 'Siga as convenções da linguagem de programação ou do projeto. Geralmente, usa-se camelCase para variáveis e funções, e PascalCase para classes, com nomes descritivos e consistentes.', '2026-03-11T17:48:22.700153+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0b099aff-f833-4955-acea-b394731f9fed', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'Qual a importância do planejamento em um projeto de programação?', 'O planejamento define o ''o quê'' e o ''como'' do projeto, estabelecendo objetivos claros, identificando os recursos necessários e um roteiro para a sua construção, minimizando riscos e retrabalho.', '2026-03-11T17:48:30.415369+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c5f47d5f-9688-4dbd-9919-b171bc7e28ae', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'O que são ''requisitos'' de um projeto?', 'Requisitos descrevem as funcionalidades, características e restrições que o software deve ter para atender às necessidades dos usuários ou do negócio.', '2026-03-11T17:48:30.415369+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a185882d-c5a2-4642-abf8-2b4341a081d4', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'Qual o significado de ''ciclo de vida de um projeto de software''?', 'É a sequência de fases pelas quais um projeto de software passa, desde a concepção até a sua implantação, manutenção e eventual desativação.', '2026-03-11T17:48:30.415369+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0a2cc57d-301a-40a6-a0bd-2d324804a39e', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'Como a prática em projetos ajuda no aprendizado de programação?', 'Projetos permitem aplicar conhecimentos teóricos em cenários reais, desenvolver habilidades de resolução de problemas, entender os desafios da integração de diferentes partes do código e refinar a lógica.', '2026-03-11T17:48:30.415369+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('83247474-a651-4620-9d9f-02f97bbcdb6a', '402bd5aa-1893-41e0-9ad8-47aa38e761fb', 'O que é um ''bug'' e como tratá-lo?', 'Um bug é um erro ou defeito em um programa. O tratamento envolve identificá-lo através de testes e depuração, corrigi-lo e, idealmente, adicioná-lo a um conjunto de testes para evitar que reapareça.', '2026-03-11T17:48:30.415369+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a0e3ee38-2bc7-4941-a973-4801ef04b3f5', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'Qual é a natureza fundamental de um algoritmo computacional?', 'Um algoritmo é uma sequência de instruções finitas, exatas e ordenadas, projetadas para resolver um problema específico.', '2026-03-11T17:55:55.164868+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('45696434-2376-41b7-b9c1-a7aadcbdfb14', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'Como um fluxograma contribui para o desenvolvimento de software?', 'Um fluxograma oferece uma representação visual detalhada da sequência lógica de um programa, facilitando a compreensão e a detecção de erros.', '2026-03-11T17:55:55.164868+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('3d10da5f-a9e2-4dac-bcef-8267e04a6a11', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'Por que a clareza na especificação do problema é vital antes de codificar?', 'A clareza garante que o objetivo final do software seja bem compreendido, direcionando o desenvolvimento para a solução correta das necessidades.', '2026-03-11T17:55:55.164868+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7c129981-bb46-4d40-88d3-f0697d26de76', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'Qual o papel das ''variáveis'' dentro da lógica de programação?', 'Variáveis são espaços de memória utilizados para armazenar dados que podem mudar durante a execução de um programa.', '2026-03-11T17:55:55.164868+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f3456bca-3238-4d9a-b5b0-25fffdeab59b', 'cec61896-1202-4bfb-ab35-c8f3eb477bec', 'O que se entende por ''estrutura de controle'' em um algoritmo?', 'Estruturas de controle (como sequências, decisões e laços) definem a ordem em que as instruções do algoritmo são executadas.', '2026-03-11T17:55:55.164868+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('127ace33-c60d-4a08-93b1-9b23860144d3', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'O que diferencia as linguagens compiladas das linguagens interpretadas?', 'Linguagens compiladas são traduzidas para código de máquina antes da execução, enquanto linguagens interpretadas são executadas linha a linha por um interpretador.', '2026-03-11T17:55:56.157066+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7ad51069-541c-486a-8a1b-c409fdece4bd', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'Qual a função de um interpretador em programação?', 'O interpretador lê e executa o código-fonte instrução por instrução, sem a necessidade de uma etapa de compilação prévia.', '2026-03-11T17:55:56.157066+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('512af8a0-4a15-4461-83f0-90cceada4be6', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'Por que é importante seguir rigorosamente a sintaxe de uma linguagem de programação?', 'Violações na sintaxe resultam em erros que impedem a compilação ou interpretação do código, pois o computador não consegue entender as instruções.', '2026-03-11T17:55:56.157066+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d8966733-9c2f-4449-945a-79ee431d7507', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'O que são ''palavras reservadas'' em uma linguagem de programação?', 'Palavras reservadas são termos com significado especial para a linguagem e não podem ser usadas como nomes de variáveis ou identificadores.', '2026-03-11T17:55:56.157066+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e37fbcf3-b4dc-416f-bb10-252306402a0d', 'f64b1b9d-580e-4ddd-9849-c6a2428b3a46', 'Em que contexto o termo ''paradigma de programação'' é utilizado?', 'Paradigma de programação refere-se a um modelo ou estilo de programação, como a programação imperativa, orientada a objetos ou funcional.', '2026-03-11T17:55:56.157066+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('74972d14-40b4-4718-b270-4f0082ce36e8', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'Qual o propósito de declarar uma variável em um programa?', 'Declarar uma variável reserva um espaço na memória para armazenar um valor que pode ser acessado e modificado durante a execução do programa.', '2026-03-11T17:55:59.48442+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('01607399-9fd4-46b3-963b-b74fb92e2fd5', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'Por que utilizamos diferentes tipos de dados em programação?', 'Diferentes tipos de dados permitem representar e manipular informações de forma adequada ao seu significado e tamanho, otimizando o uso da memória e a velocidade de processamento.', '2026-03-11T17:55:59.48442+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d484a567-3043-4d62-a35d-9a7b92a36657', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'Qual o tipo de dado adequado para representar um percentual como 75,5%?', 'Um tipo de dado de ponto flutuante (como float ou double) é o mais apropriado para representar números com casas decimais, como percentuais.', '2026-03-11T17:55:59.48442+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('9bbc2820-a43b-4524-a1a7-ae420b8577c1', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'O que acontece se tentarmos atribuir um valor de texto a uma variável numérica?', 'Geralmente, ocorrerá um erro de tipo (type error) porque a linguagem de programação não sabe como realizar operações numéricas com um dado textual.', '2026-03-11T17:55:59.48442+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4bb03b7c-3804-4105-b7d4-bc9c146dd8da', 'eaf719fa-fe23-427b-939b-4e5c805b9b3b', 'Como a memória é gerenciada ao utilizar variáveis em um programa?', 'O sistema operacional e a própria linguagem de programação gerenciam a alocação e desalocação da memória necessária para as variáveis.', '2026-03-11T17:55:59.48442+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('9775be9b-eb7a-409c-b72f-e82ef63d8271', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'Qual o propósito de utilizar a estrutura ''if-else''?', 'A estrutura ''if-else'' permite que um programa execute um conjunto de instruções se uma condição for verdadeira e outro conjunto se ela for falsa.', '2026-03-11T17:56:35.263222+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0c9ee55b-7f62-45ba-84c4-7b35caf8f778', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'Como o operador ternário (condicional) pode simplificar o código?', 'Ele permite escrever uma instrução condicional de forma mais concisa em uma única linha, útil para atribuições simples.', '2026-03-11T17:56:35.263222+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7a20a48e-3e3a-4424-bb45-3e320e0682ae', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'Por que a ordem das condições em uma estrutura ''if-else if-else'' é importante?', 'A ordem determina qual condição será avaliada primeiro. A primeira condição verdadeira determinara qual bloco de código será executado, e as demais não serão mais verificadas.', '2026-03-11T17:56:35.263222+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('2f92376f-67d6-4d68-ac1c-4f4cf7393c74', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'O que é um ''encadeamento aninhado'' de estruturas condicionais?', 'É quando uma estrutura condicional (if, else if, else) está localizada dentro de outra estrutura condicional, permitindo lógicas mais complexas.', '2026-03-11T17:56:35.263222+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('9de4203a-0256-44ca-bb1a-304ec9a0e4b2', '4affce83-8aa7-4f1b-97d5-b36c91115af3', 'Qual o resultado esperado de um ''if'' sem um bloco ''else'' associado?', 'Se a condição do ''if'' for falsa, nenhuma instrução dentro desse bloco será executada, e o programa continuará sua execução após o bloco ''if''.', '2026-03-11T17:56:35.263222+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e9f2ea19-0af0-4eb8-bc99-49fee8a20f84', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'Para que servem os operadores de comparação em programação?', 'Operadores de comparação (como ==, !=, >, <, >=, <=) são usados para comparar dois valores e retornar um resultado booleano (verdadeiro ou falso).', '2026-03-11T17:56:39.020137+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('57a1765d-f0fc-406f-8815-2de1d4a1dbbb', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'Qual a diferença entre o operador de atribuição (=) e o operador de igualdade (==)?', 'O operador de atribuição (=) define o valor de uma variável, enquanto o operador de igualdade (==) verifica se dois valores são iguais.', '2026-03-11T17:56:39.020137+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('b468efb9-8547-4b14-98f0-653f59c13321', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'Como o operador lógico ''OU'' (OR) funciona?', 'O operador ''OU'' retorna verdadeiro se pelo menos um dos operandos for verdadeiro. Ele só retorna falso se ambos os operandos forem falsos.', '2026-03-11T17:56:39.020137+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('18cf7f96-4dce-455f-8cef-b13906ea0622', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'O que é ''expressão'' em programação?', 'Uma expressão é uma combinação de valores, variáveis, operadores e chamadas de função que resulta em um único valor.', '2026-03-11T17:56:39.020137+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('8b7dff31-90b4-4f79-8d53-ba55ec5efd13', '821eebe6-4dfc-4ff7-b8e8-99c84a9a2936', 'Qual a utilidade dos operadores de incremento e decremento (++, --)?', 'São atalhos para aumentar ou diminuir o valor de uma variável numérica em uma unidade, usados frequentemente em laços de repetição.', '2026-03-11T17:56:39.020137+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7f47e2df-0b9b-4c6d-a413-4e7c30745e15', '7b8be525-9faa-4327-acba-376d5dd240e2', 'Qual a finalidade principal dos laços de repetição em programação?', 'Laços de repetição permitem executar um conjunto de instruções múltiplas vezes sem a necessidade de reescrever o código, automatizando tarefas e otimizando o trabalho.', '2026-03-11T17:56:39.864433+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a7fcf97e-22a3-4307-abe9-65de24879510', '7b8be525-9faa-4327-acba-376d5dd240e2', 'Em que cenário um ''laço infinito'' pode ocorrer e por que é indesejável?', 'Um laço infinito ocorre quando a condição de parada nunca é atingida, fazendo o programa travar ou consumir recursos excessivamente. É indesejável na maioria dos casos.', '2026-03-11T17:56:39.864433+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('9a05b1a4-c3cc-4191-b964-b1a80e2c90a2', '7b8be525-9faa-4327-acba-376d5dd240e2', 'O que o laço ''do-while'' garante que aconteça pelo menos uma vez?', 'O laço ''do-while'' garante que o bloco de código dentro dele seja executado pelo menos uma vez antes que a condição seja verificada pela primeira vez.', '2026-03-11T17:56:39.864433+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('1a1f5c6a-4a4d-41b9-859a-c5192939abea', '7b8be525-9faa-4327-acba-376d5dd240e2', 'Como podemos usar um laço ''for'' para percorrer os elementos de uma lista ou array?', 'Configurando o ''for'' para iterar do índice inicial (geralmente 0) até o último índice válido do array, acessando cada elemento em cada iteração.', '2026-03-11T17:56:39.864433+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ff277f02-6192-4e62-9018-d5f68b5f7bf0', '7b8be525-9faa-4327-acba-376d5dd240e2', 'Qual a importância de atualizar variáveis de controle dentro de laços para evitar ''laços infinitos''?', 'É crucial garantir que a condição de parada do laço seja eventualmente alcançada, e isso geralmente depende da atualização correta das variáveis que compõem a condição.', '2026-03-11T17:56:39.864433+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a8403485-c7ac-444b-9556-ba9af80162fd', '1e220f09-6464-4328-8b04-2b8c5749e869', 'O que define uma função em programação?', 'Uma função é um bloco de código nomeado que realiza uma tarefa específica e pode ser executado várias vezes através de uma chamada.', '2026-03-11T17:57:22.490606+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('a91e74c4-2923-48de-83b9-44b2cfa39f70', '1e220f09-6464-4328-8b04-2b8c5749e869', 'Qual o conceito de ''escopo de variável'' em relação às funções?', 'O escopo de variável define onde uma variável é acessível no código. Variáveis declaradas dentro de uma função geralmente têm escopo local e só podem ser usadas dentro dessa função.', '2026-03-11T17:57:22.490606+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('64fb5cf7-14bb-4119-b338-0587af476e37', '1e220f09-6464-4328-8b04-2b8c5749e869', 'O que acontece se uma função não tiver uma instrução ''return'' explícita?', 'A função retorna um valor especial (como ''undefined'' em JavaScript ou ''None'' em Python), indicando que nenhum valor foi explicitamente retornado.', '2026-03-11T17:57:22.490606+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7c83aab6-1173-4b18-b94b-dcef039277c8', '1e220f09-6464-4328-8b04-2b8c5749e869', 'Como a passagem de ''argumentos'' difere de ''parâmetros''?', 'Parâmetros são as variáveis definidas na declaração da função (''def minha_funcao(parametro1):''), enquanto argumentos são os valores reais passados para esses parâmetros quando a função é chamada (''minha_funcao(argumento1)'').', '2026-03-11T17:57:22.490606+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4fe4ed5c-e157-43d8-875c-0d5449b465fb', '1e220f09-6464-4328-8b04-2b8c5749e869', 'Por que as funções contribuem para a ''modularidade'' do software?', 'Elas dividem um programa complexo em partes menores e gerenciáveis, cada uma focada em uma funcionalidade, facilitando o desenvolvimento, teste e manutenção.', '2026-03-11T17:57:22.490606+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f630336d-053a-4ed2-b171-71ffed96937c', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'O que é um ''array'' ou ''lista'' em programação?', 'Uma estrutura de dados que armazena uma coleção de elementos do mesmo tipo ou de tipos diferentes em uma ordem específica, acessíveis por um índice.', '2026-03-11T17:57:26.149565+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('5645a742-608f-43ed-8860-6b74e5d25dd0', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'Qual a principal característica de um ''dicionário'' (ou mapa, objeto)?', 'É uma coleção de pares chave-valor, onde cada valor é associado a uma chave única. O acesso aos valores é feito diretamente pela chave.', '2026-03-11T17:57:26.149565+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('7fb1b2c7-fed6-463c-89ea-179ee3a3f814', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'Por que é importante dar nomes significativos às variáveis e funções?', 'Nomes descritivos tornam o código mais legível, ajudando a entender a finalidade de cada elemento sem a necessidade de consultar extensas documentações.', '2026-03-11T17:57:26.149565+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d120a296-c51e-4d56-8ec1-f820f93054a9', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'O que significa ''código limpo'' (clean code)?', 'Código limpo é aquele que é fácil de ler, entender, testar e modificar, escrito com clareza, simplicidade e seguindo convenções estabelecidas.', '2026-03-11T17:57:26.149565+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('8e0b239c-ddbd-47fc-b160-5ddd78f4a463', '6f1489ca-5bd3-4b42-851f-e48d2c7bb46b', 'Como a indentação contribui para a legibilidade do código?', 'A indentação correta agrupa visualmente blocos de código (como dentro de laços, condicionais ou funções), indicando a estrutura e o fluxo do programa, tornando-o mais fácil de seguir.', '2026-03-11T17:57:26.149565+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('8b23573b-1cb9-4442-ad89-9ae5afecdfd1', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'What are the main components of the BANT framework?', 'Budget, Authority, Need, and Timeline.', '2026-03-12T04:41:31.766441+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('539537b5-d619-47c9-9021-762b20ba99b4', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'What is the primary psychological spark that drives initial interest in a B2B negotiation?', 'The perception of a problem or an opportunity for improvement that your product or service can solve or maximize.', '2026-03-12T04:41:34.283896+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('d55430be-7935-4b95-9a0d-17023480f8ee', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'Briefly describe the purpose of the **''Economic Buyer''** in the MEDDIC framework.', 'The ''Economic Buyer'' is the person within the customer''s organization who has the final authority to approve the financial expenditure for the purchase.', '2026-03-12T04:41:35.022225+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c291f162-331b-44c5-9d90-ba2bd3f83e1b', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'What does ''empathy'' mean in the context of B2B sales?', 'The ability to understand and share the feelings, perspectives, and challenges of your interlocutor by putting yourself in their shoes.', '2026-03-12T04:41:37.193213+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('95b4a913-ef16-4c89-9003-8a0592539c49', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'In which phase of SPIN Selling do the questions focus on the negative consequences of an unresolved problem?', 'In the ''Implication'' phase.', '2026-03-12T04:41:38.026189+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c87ffe88-5af9-4598-931d-b9486d9e7df5', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'Why is proper lead qualification essential to optimize the time of the B2B sales team?', 'Because it allows salespeople to prioritize and direct their efforts toward opportunities with a higher probability of conversion, avoiding the waste of resources on unqualified leads.', '2026-03-12T04:41:41.077317+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('701d9748-d23b-4749-b6cc-bbfbb52847c5', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'Why is active listening more effective than simply hearing in B2B negotiations?', 'Because it demonstrates respect, creates clarity in communication, and allows for the identification of underlying needs and concerns that may not be explicitly stated.', '2026-03-12T04:41:41.098946+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('cfeabf19-0e9c-4a9e-b467-8a4cd13c4107', '0b91a2bd-cd84-407d-9faf-b1ef04ed3c36', 'What is the fundamental difference between qualifying a lead and discovering an opportunity in B2B sales?', 'Qualifying is determining if the client fits the ideal criteria to become a customer. Discovering an opportunity is identifying a specific need and a business potential that can be addressed by your solution.', '2026-03-12T04:41:44.311624+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('c21fc238-bc4c-4c91-94f8-b64135c54088', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'What is the main obstacle in building trust with multiple stakeholders in a B2B account?', 'Manage the different priorities, concerns, and levels of influence of each individual involved in the decision-making process.', '2026-03-12T04:41:44.413325+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('397871dd-daeb-4e8f-adda-f614b58b0057', 'b68c357c-ed3f-48e6-9c4a-9ac96ce14aa7', 'How do soft skills impact B2B negotiation?', 'They are crucial for establishing rapport, managing conflicts, demonstrating emotional intelligence, and creating a collaborative environment, directly impacting the quality of the agreement and the post-sales relationship.', '2026-03-12T04:41:47.601303+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('bcaeacd8-ce39-4f29-a06e-f2194e4110e7', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'What are the two main types of sales objections in B2B?', 'Genuine objections (the client truly has a concern) and courtesy or evasive objections (an excuse not to move forward).', '2026-03-12T04:42:24.579595+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('26bc346a-2afa-4d88-bb57-d5cccda10953', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'What is the main objective of identifying the root cause of an objection?', 'Understand the customer''s true concern in order to address it effectively, rather than responding to a superficial symptom.', '2026-03-12T04:42:27.444464+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e68eee45-8ad8-4cb3-b2c8-f9ec6d049e9e', '86104405-5e60-496d-954b-cdac7965204c', 'What are Robert Cialdini''s six main principles of persuasion?', 'Reciprocity, Commitment and Consistency, Social Proof, Liking, Authority, and Scarcity.', '2026-03-12T04:42:28.431691+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('4481100c-de21-4c9b-8326-26d5b48cc73f', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'How does the ''Feel, Felt, Found'' technique help manage objections?', 'It validates the customer''s emotion (''I felt''), shows that others had the same concern (''Felt''), and presents the solution based on successful experiences (''Found'').', '2026-03-12T04:42:30.556455+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('dd0fd4f9-886c-4cb9-8ab9-3dd0ed9a4898', '86104405-5e60-496d-954b-cdac7965204c', 'How can ''Authority'' be used ethically in a B2B negotiation?', 'Through the demonstration of expertise, credentials, industry knowledge, and proven results by your company or recognized specialists.', '2026-03-12T04:42:31.485843+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('2323cd27-b66b-42cb-b355-4a81e894d395', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'When should the price be introduced in a B2B negotiation to minimize cost objections?', 'Ideally, after having clearly demonstrated the value and benefits of the solution, and when the client already expresses strong interest and need.', '2026-03-12T04:42:33.648815+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('79ff1b89-aabf-4c6e-a725-afc7f736b119', '86104405-5e60-496d-954b-cdac7965204c', 'In what way can ''Commitment and Consistency'' be applied in B2B sales in an ethical manner?', 'Encouraging the customer to make small initial verbal or written commitments that are consistent with the final purchase goal, such as agreeing with the need or the next step in the process.', '2026-03-12T04:42:34.755448+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('e397d216-bfbd-49e1-bc82-8c3bd86724de', 'fea06b96-db23-44e2-b150-791e2fa4207c', 'What is the importance of preparing for common objections before a B2B sales meeting?', 'It allows the salesperson to anticipate challenges, formulate concise and confident responses, and maintain calm and control during the negotiation, increasing the probability of success.', '2026-03-12T04:42:36.847276+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('8d922599-fdeb-4788-8655-eed549d96bfc', '86104405-5e60-496d-954b-cdac7965204c', 'What is the difference between ethical persuasion and manipulation?', 'Ethical persuasion focuses on positively influencing the buyer so that they make a decision that is beneficial for both sides, based on transparency and truth. Manipulation seeks to deceive or pressure the buyer for unilateral benefit.', '2026-03-12T04:42:37.569737+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('f0e4334c-b406-463c-a8d1-c64eaba31ccc', '86104405-5e60-496d-954b-cdac7965204c', 'How can granting small favors or valuable information boost the principle of ''Reciprocity'' in B2B sales?', 'By offering something of value upfront, such as a market insight, a useful tool, or a strategic tip, you create a tendency in the buyer to want to reciprocate, clearing the path for your proposal.', '2026-03-12T04:42:40.686671+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('531eb8cf-8437-4591-9800-1d89083f5a01', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'What is the difference between a ''win-lose agreement'' and a ''win-win agreement'' in B2B negotiations?', 'In a win-lose agreement, one party obtains significant advantages at the expense of the other. In a win-win agreement, both parties achieve satisfactory and beneficial results, strengthening the relationship.', '2026-03-12T04:43:19.853344+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('2e56b428-f201-4cb6-9567-35c6792adcff', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'What is a ''BATNA'' (Best Alternative To a Negotiated Agreement) and why is it important?', 'BATNA is the best alternative a negotiator has in case the negotiation fails. Knowing your BATNA provides power and a reference point for evaluating offers during the negotiation.', '2026-03-12T04:43:22.82368+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('0e987bb6-7c55-46a3-8644-db54a45e9cee', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'What are the typical phases of a B2B sales negotiation cycle?', 'Preparation, Exploration, Proposal, Bargaining, and Closing.', '2026-03-12T04:43:25.493405+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('ec753e6d-0211-44d6-95ca-5fc5c40edb1b', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'How does expectation management during B2B negotiation impact the final outcome?', 'Managing expectations realistically and transparently helps avoid frustration, build trust, and keep both parties focused on achieving a viable and satisfying long-term agreement.', '2026-03-12T04:43:28.680062+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_flashcards" ("id", "module_id", "front", "back", "created_at") VALUES ('922f4b1b-2121-4673-b5ed-b93b5b6de65b', '29f563d8-00c0-4eb2-a0d2-123d99e1df44', 'What is the importance of a post-sales plan after closing a B2B negotiation?', 'It ensures customer satisfaction, opens doors for new business opportunities (upsell/cross-sell), strengthens the relationship and builds loyalty, in addition to potential referrals.', '2026-03-12T04:43:31.795512+00:00') ON CONFLICT DO NOTHING;

